// SCP Card Data
const SCPS = [
  { id:"SCP-999", name:"Tickle Monster", cls:"safe", cost:2, desc:"触れた者に多幸感を与える橙色のスライム状生物。あらゆる精神的苦痛を癒す力を持つ。", power:"対象を幸福感で包み込み、敵の攻撃意欲を完全に消失させる。精神系攻撃を無効化する。", desc_en:"A large, amorphous, gelatinous mass of translucent orange slime. Contact with SCP-999 immediately engenders a sense of euphoria and cures all forms of psychological distress.", power_en:"Envelops the target in waves of overwhelming joy, completely nullifying hostile intent. Renders all psychic attacks ineffective." },
  { id:"SCP-914", name:"The Clockworks", cls:"safe", cost:3, desc:"巨大な時計仕掛けの機械。入力された物体を5段階の設定で変換する。", power:"相手のSCPを「粗い」設定で弱体化、または味方を「非常に細かい」で強化する。", desc_en:"A large clockwork device consisting of an intake booth, an output booth, and a large brass dial with five settings: Rough, Coarse, 1:1, Fine, and Very Fine.", power_en:"Processes enemy SCPs on 'Rough' to degrade them, or refines allies on 'Very Fine' to enhance their capabilities." },
  { id:"SCP-2295", name:"The Bear", cls:"safe", cost:2, desc:"パッチワークのテディベア。傷ついた人の臓器をぬいぐるみの素材で再現し治癒する。", power:"味方の損傷を即座に修復する。致命傷も布製の代替臓器で回復させる。", desc_en:"A patchwork stuffed bear capable of anomalously producing functional replicas of organs from fabric and stuffing materials to heal injured persons.", power_en:"Instantly repairs ally damage by crafting replacement organs from cloth and stuffing. Even fatal wounds are healed." },
  { id:"SCP-131", name:"Eye Pods", cls:"safe", cost:1, desc:"涙滴型の小型生物のペア。大きな目を持ち、常に対象を見つめ続ける。", power:"対象から決して目を離さず、視線を要する収容（SCP-173等）を完璧に補助する。", desc_en:"A pair of teardrop-shaped creatures, each with a single large eye. They are friendly, curious, and never blink, providing unbroken line of sight.", power_en:"Maintains unblinking visual contact with the target, perfectly assisting containment of sight-dependent SCPs like SCP-173." },
  { id:"SCP-049", name:"Plague Doctor", cls:"euclid", cost:5, desc:"中世の疫病医師の姿をした人型実体。触れた生物を即死させ「治療済み」のゾンビにする。", power:"触れた対象を即死させる「治療」を施す。死亡した対象はアンデッドの従僕として蘇る。", desc_en:"A humanoid entity resembling a medieval plague doctor. Its touch is invariably lethal, after which it performs 'surgery' to reanimate victims as shambling undead (SCP-049-2).", power_en:"Administers its lethal 'cure' through physical contact. Deceased targets are reanimated as undead servants." },
  { id:"SCP-173", name:"The Sculpture", cls:"euclid", cost:4, desc:"コンクリートと鉄筋で構成された彫刻。直接視認されていない間に高速移動し、対象の首を折る。", power:"視線が外れた瞬間に超高速で移動し、対象の頸部を破壊する。直接視認でのみ抑制可能。", desc_en:"A concrete and rebar sculpture animate and extremely hostile. It cannot move while within a direct line of sight but will snap the neck of personnel when unobserved.", power_en:"Moves at extreme speed the instant line of sight is broken, crushing the target's neck. Can only be suppressed by direct visual observation." },
  { id:"SCP-096", name:"Shy Guy", cls:"euclid", cost:6, desc:"痩せ細った人型実体。顔を見られると激昂し、対象が死ぬまで追跡を止めない。", power:"顔を視認した対象を地球上どこまでも追跡し、到達後に[データ削除済]する。阻止不可能。", desc_en:"An emaciated humanoid that enters a rage state when its face is viewed by any means. It will pursue the viewer across any distance until the target is deceased.", power_en:"Pursues anyone who views its face to any point on Earth. Upon reaching the target, [DATA EXPUNGED]. Cannot be stopped." },
  { id:"SCP-035", name:"Possessive Mask", cls:"euclid", cost:5, desc:"白い喜劇のマスク。装着者の精神を完全に支配し、周囲の物質を腐食させる。", power:"対象の精神を乗っ取り完全に支配する。周囲に強力な腐食性物質を分泌する。", desc_en:"A white porcelain comedy mask that exerts a compulsive effect on nearby persons to put it on. The wearer is completely dominated, and the mask secretes a highly corrosive substance.", power_en:"Seizes total control of the target's mind. Secretes powerful corrosive material that degrades all surrounding matter." },
  { id:"SCP-682", name:"Hard Reptile", cls:"keter", cost:8, desc:"巨大な爬虫類型生物。あらゆる手段での破壊に適応・再生し、全生命体への激しい敵意を持つ。", power:"受けたダメージに対して即座に適応・耐性を獲得する。物理的破壊は事実上不可能。", desc_en:"A large, vaguely reptile-like creature of unknown origin. Extremely hostile to all life, possessing high intelligence, strength, and reflexes. Adapts to and regenerates from all forms of damage.", power_en:"Instantly adapts to and develops resistance against any damage sustained. Physical destruction is virtually impossible.", image:"assets/cards/scp-682.jpg", imageCredit:"OccultistMave", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-682" },
  { id:"SCP-106", name:"The Old Man", cls:"keter", cost:7, desc:"老人の姿をした人型実体。物質を腐食させ、自身のポケットディメンションに対象を引きずり込む。", power:"あらゆる物質を通過・腐食し、対象をポケットディメンション（個人的な拷問空間）に引き込む。", desc_en:"An elderly humanoid that causes a corrosion effect on all solid matter it touches. Capable of passing through solid matter and dragging victims into a personal pocket dimension.", power_en:"Passes through and corrodes any solid matter, pulling targets into its pocket dimension — a personal torture space.", image:"assets/cards/scp-106.jpg", imageCredit:"Klay Abele (MrKlay)", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-106" },
  { id:"SCP-076", name:"Able", cls:"keter", cost:7, desc:"古代の戦士。死亡しても石棺から再生する。虚空から武器を生成し超人的な戦闘能力を持つ。", power:"虚空から無数の近接武器を生成し、超人的な速度と力で戦闘する。死亡後も再生する。", desc_en:"A Semitic male contained within a stone coffin (SCP-076-1). Upon activation, manifests bladed weapons from thin air and displays superhuman combat abilities. Regenerates within SCP-076-1 after termination.", power_en:"Manifests countless melee weapons from thin air, fighting with superhuman speed and strength. Regenerates after death." },
  { id:"SCP-2399", name:"Martian Destroyer", cls:"keter", cost:9, desc:"木星大赤斑内に存在する超巨大兵器。修復プロセスが完了すれば惑星を破壊可能。", power:"惑星規模の破壊力を持つ超兵器。電磁パルスと反物質弾頭で全てを消滅させる。", desc_en:"A massive mechanical weapon lodged within Jupiter's Great Red Spot, currently undergoing self-repair. Capable of planetary destruction upon full restoration.", power_en:"Planet-scale superweapon. Annihilates everything with electromagnetic pulses and antimatter warheads.", image:"assets/cards/scp-2399.png", imageCredit:"djkaktus", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-2399" },
  { id:"SCP-343", name:"God", cls:"thaumiel", cost:10, desc:"自らを「神」と称する男性型実体。現実改変能力を持ち、あらゆる望みを実現可能。", power:"現実そのものを書き換える全能の力。あらゆる事象を思い通りに操作する。", desc_en:"A male humanoid who claims to be 'God.' Possesses apparent omnipotence — able to reshape reality, create and destroy matter at will, and seemingly alter the fabric of existence itself.", power_en:"Rewrites reality itself with omnipotent power. Manipulates any event or outcome at will." },
  { id:"SCP-179", name:"Sauelsuepp", cls:"thaumiel", cost:8, desc:"太陽付近に浮遊する女性型実体。地球への脅威を事前に指差して警告する。", power:"宇宙規模の脅威を事前に感知し警告する。太陽エネルギーを防御障壁として展開する。", desc_en:"A female humanoid entity located near the Sun. Points toward approaching cosmic threats to Earth, providing early warning of extraterrestrial dangers.", power_en:"Detects and warns of cosmic-scale threats in advance. Deploys solar energy as a defensive barrier." },
  // ===== 追加20体 =====
  { id:"SCP-500", name:"Panacea", cls:"safe", cost:3, desc:"万能薬の赤い錠剤。あらゆる疾病・感染・異常状態を完全に治癒する。残り47錠。", power:"あらゆる状態異常・デバフを即座に無効化。味方を完全回復させる。", desc_en:"A small plastic can containing 47 red pills. When taken, one pill cures any disease, infection, or anomalous condition in the subject.", power_en:"Instantly neutralizes all status ailments and debuffs. Fully restores an ally to perfect condition." },
  { id:"SCP-529", name:"Josie the Half-Cat", cls:"safe", cost:1, desc:"後半身が存在しない猫。切断面はなく、単に「そこで終わっている」。極めて友好的。", power:"存在の境界を曖昧にし、攻撃が半分すり抜ける。敵の照準を狂わせる。", desc_en:"A small house cat whose body terminates at roughly the midsection. There is no wound; the cat simply 'stops.' Extremely friendly and in good health.", power_en:"Blurs the boundary of existence, causing attacks to phase through. Disrupts enemy targeting." },
  { id:"SCP-1048", name:"Builder Bear", cls:"safe", cost:2, desc:"小さなテディベア。人懐っこく振る舞うが、恐ろしい複製体を素材から作り出す。", power:"周囲の素材から戦闘用の複製体を生成する。見た目に反して極めて危険。", desc_en:"A small teddy bear that is affectionate toward Foundation personnel. However, it constructs horrific duplicate bears from materials including human ears and fetuses.", power_en:"Creates combat duplicates from surrounding materials. Extremely dangerous despite its innocent appearance." },
  { id:"SCP-458", name:"The Never-Ending Pizza Box", cls:"safe", cost:1, desc:"開けると持ち主が最も食べたいピザが出現する箱。補給に最適。", power:"味方の士気と体力を回復する無限の補給源。長期戦で真価を発揮する。", desc_en:"A large pizza box from Little Caesar's that generates a pizza matching the holder's current preference whenever opened. An inexhaustible supply source.", power_en:"An infinite supply source that restores ally morale and stamina. Excels in prolonged engagements." },
  { id:"SCP-085", name:"Hand-drawn Cassy", cls:"safe", cost:2, desc:"紙の中に生きる手描きの女性。二次元世界を自由に移動し、描かれた物を操作する。", power:"二次元空間に退避し攻撃を回避。描かれた武器や罠を具現化して攻撃する。", desc_en:"A sentient female figure drawn in pencil and ink, 'living' within two-dimensional surfaces. Can move between connected drawings and interact with depicted objects.", power_en:"Retreats into 2D space to evade attacks. Manifests drawn weapons and traps to strike enemies." },
  { id:"SCP-939", name:"With Many Voices", cls:"euclid", cost:5, desc:"大型の無眼捕食者群。過去の犠牲者の声を模倣して獲物を誘い出す。", power:"犠牲者の声で敵を誘引・混乱させる。強力な顎と毒で対象を制圧する。", desc_en:"Large, eyeless, pack-hunting predators that lure prey by mimicking the voices of their previous victims. Possess powerful jaws and an amnestic compound in their exhalation.", power_en:"Lures and disorients enemies using victims' mimicked voices. Subdues targets with powerful jaws and toxins." },
  { id:"SCP-066", name:"Eric's Toy", cls:"euclid", cost:3, desc:"毛糸の塊状の生物。「エリック？」と呼びかけると予測不能な音響攻撃を放つ。", power:"破壊的な音波攻撃を放つ。ベートーヴェン第九を致死的音量で再生する。", desc_en:"An amorphous mass of yarn that asks 'Eric?' when approached. Produces unpredictable and dangerous sonic effects, including Beethoven's 9th Symphony at lethal volumes.", power_en:"Unleashes destructive sonic attacks. Plays Beethoven's 9th Symphony at lethal volume." },
  { id:"SCP-294", name:"The Coffee Machine", cls:"euclid", cost:4, desc:"あらゆる液体を生成可能な自販機。「液体幸福」から「液体反物質」まで。", power:"要求された任意の液体を生成。「液体苦痛」「液体死」など攻撃的な液体も可能。", desc_en:"A standard coffee vending machine with a QWERTY keyboard. Capable of dispensing any liquid requested by typing, from 'liquid happiness' to 'liquid antimatter.'", power_en:"Generates any requested liquid on demand. Offensive options include 'liquid pain' and 'liquid death.'" },
  { id:"SCP-087", name:"The Stairwell", cls:"euclid", cost:4, desc:"終わりのない下り階段。暗闇の中に顔のような存在が潜む。探索者は帰還できない。", power:"対象を無限の暗闇に引き込み、精神を蝕む。脱出は不可能。", desc_en:"An unlit staircase that descends endlessly. A face-like entity lurks in the darkness below. No exploration team sent past a certain depth has returned.", power_en:"Drags targets into infinite darkness, eroding their sanity. Escape is impossible." },
  { id:"SCP-1471", name:"MalO ver1.0.0", cls:"euclid", cost:3, desc:"インストールすると黒い頭蓋骨の実体が視界に現れ始めるアプリ。実害はないが精神的圧迫。", power:"対象の視界に常に出現し、精神的に追い詰める。集中力を著しく低下させる。", desc_en:"A mobile app that, once installed, sends images of SCP-1471-A — a humanoid with a canid skull — appearing progressively closer. Eventually visible to the naked eye.", power_en:"Constantly appears in the target's field of vision, causing severe psychological pressure and drastically reducing focus." },
  { id:"SCP-953", name:"Polymorphic Humanoid", cls:"keter", cost:6, desc:"九尾の狐の姿を持つ変身能力者。人間に化けて獲物の肝臓を摘出・捕食する。", power:"あらゆる姿に変身し敵を欺く。油断した対象の臓器を瞬時に摘出する。", desc_en:"A nine-tailed fox (kumiho) capable of assuming any humanoid form. Lures victims with seduction and extracts their livers for consumption.", power_en:"Shape-shifts into any form to deceive enemies. Instantly extracts organs from unsuspecting targets." },
  { id:"SCP-610", name:"The Flesh that Hates", cls:"keter", cost:7, desc:"接触感染する肉塊の疫病。感染者は肉の怪物に変異し、さらに感染を拡大する。", power:"接触した対象を肉の怪物に変異させる。感染は指数関数的に拡大する。", desc_en:"A contagious skin disease that transforms infected hosts into grotesque masses of undifferentiated flesh. The infection spreads through physical contact exponentially.", power_en:"Mutates contacted targets into flesh abominations. Infection spreads exponentially.", image:"assets/cards/scp-610.png", imageCredit:"stephlynch & Austin Beaulier", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-610" },
  { id:"SCP-1000", name:"Bigfoot", cls:"keter", cost:6, desc:"かつて高度文明を築いた類人猿種族。人類によって滅ぼされたが、密かに復活を企てる。", power:"古代の超技術を用いた攻撃。知性と力を兼ね備えた戦術で対象を圧倒する。", desc_en:"A species of sapient hominids (Bigfoot) that once built an advanced civilization. Destroyed by humanity using SCP-1000 long ago, they now secretly work toward restoration.", power_en:"Attacks with ancient super-technology. Overwhelms targets with a combination of intelligence and brute strength.", image:"assets/cards/scp-1000.png", imageCredit:"Shaggydredlocks", imageLicense:"CC BY-SA 2.0", imageSource:"https://scp-wiki.wikidot.com/scp-1000" },
  { id:"SCP-2317", name:"Door to Darkness", cls:"keter", cost:9, desc:"次元の向こうに封印された世界を滅ぼす存在。封印は間もなく解ける。", power:"次元を超越する終末的な破壊力。封印が解ければ全てが終わる。", desc_en:"A wooden door leading to a pocket dimension containing a chained entity of apocalyptic power. The chains are failing. There is no known method of prevention.", power_en:"Wields apocalyptic destructive force that transcends dimensions. When the seal breaks, everything ends." },
  { id:"SCP-3000", name:"Anantashesha", cls:"keter", cost:8, desc:"ベンガル湾深海に棲む全長数百kmの巨大ウナギ。接近者の記憶と自我を溶解する。", power:"対象の記憶と自我を分解・吸収する。精神は完全に消滅し、アミラーゼを分泌する。", desc_en:"A massive, serpentine entity several hundred kilometers long residing in the Bay of Bengal. Proximity causes progressive memory loss and dissolution of identity. Produces Y-909 compound.", power_en:"Decomposes and absorbs the target's memories and sense of self. The psyche is completely annihilated.", image:"assets/cards/scp-3000.png", imageCredit:"djkaktus", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-3000" },
  { id:"SCP-2000", name:"Deus Ex Machina", cls:"thaumiel", cost:9, desc:"イエローストーン地下の人類再生施設。文明崩壊時に人類を一から再構築する。", power:"文明そのものをリセットし再構築する。究極のやり直し能力。", desc_en:"A Foundation facility beneath Yellowstone designed to rebuild human civilization from scratch following an XK-class end-of-the-world scenario. Has been activated at least twice.", power_en:"Resets and reconstructs civilization itself. The ultimate do-over capability.", image:"assets/cards/scp-2000.jpg", imageCredit:"Colin Grice & HammerMaiden", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-2000" },
  { id:"SCP-073", name:"Cain", cls:"thaumiel", cost:6, desc:"聖書のカインを名乗る人型実体。体に刻まれた古代文字により、受けたダメージが攻撃者に反射される。", power:"受けた全ダメージを攻撃者に反射する。近くの植物は枯れ、有機物が腐敗する。", desc_en:"A male humanoid claiming to be Cain of biblical legend. Covered in Sumerian script, any damage dealt to SCP-073 is reflected back upon the attacker. Causes nearby plant life to wither.", power_en:"Reflects all received damage back to the attacker. Nearby vegetation dies and organic matter decays." },
  { id:"SCP-105", name:"Iris Thompson", cls:"thaumiel", cost:5, desc:"写真を通じて遠隔操作能力を持つ若い女性。財団の機動部隊Omega-7に所属。", power:"写真を媒介に遠隔地の物体を操作する。偵察・工作に極めて有効。", desc_en:"A young woman capable of manipulating objects remotely through photographs. Former member of Mobile Task Force Omega-7 ('Pandora's Box').", power_en:"Manipulates distant objects through photographs as a medium. Extremely effective for reconnaissance and sabotage.", image:"assets/cards/scp-105.jpg", imageCredit:"Retro00064", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-105" },
  { id:"SCP-662", name:"Mr. Deeds", cls:"thaumiel", cost:4, desc:"銀の呼び鈴。鳴らすとMr.Deedsと名乗る執事が現れ、人間的に可能なあらゆる依頼を完遂する。", power:"完璧な執事を召喚し、あらゆる支援任務を遂行させる。戦術的サポートに優れる。", desc_en:"A small silver handbell. When rung, a butler named Mr. Deeds appears and fulfills any request within the limits of a normal human's capabilities.", power_en:"Summons a flawless butler to execute any support mission. Excels at tactical assistance." },
  { id:"SCP-500-D", name:"Overwritten Alloy", cls:"thaumiel", cost:7, desc:"SCP-914で「非常に細かい」設定で精製された合金。異常な防御特性を持つ。", power:"あらゆる異常攻撃を吸収・無効化する超合金の障壁を展開する。", desc_en:"An alloy refined through SCP-914 on the 'Very Fine' setting. Exhibits extraordinary defensive properties against anomalous effects.", power_en:"Deploys a super-alloy barrier that absorbs and neutralizes all anomalous attacks." },
  // ===== シリーズI 追加 =====
  { id:"SCP-001", name:"The Gate Guardian", cls:"thaumiel", cost:10, desc:"エデンの園の門を守る巨大な光の存在。燃える剣を持ち、あらゆる接近者を消滅させる。", power:"天使の炎剣であらゆる存在を原子レベルで消滅させる。全知に近い知覚能力を持つ。", desc_en:"A colossal luminous entity guarding the gate to Eden, wielding a flaming sword. Any being that approaches is annihilated at the subatomic level.", power_en:"Annihilates any entity at the atomic level with its angelic flaming sword. Possesses near-omniscient perception." },
  { id:"SCP-002", name:"The Living Room", cls:"euclid", cost:4, desc:"肉塊で構成された部屋。内部の家具は全て人体組織から形成されている。侵入者を吸収する。", power:"侵入者を壁面に吸収・同化し、新たな家具として再構成する。", desc_en:"A fleshy, tumor-like growth containing a living space. All furniture inside is composed of human tissue and bone. Absorbs intruders and converts them into new furnishings.", power_en:"Absorbs and assimilates intruders into its walls, reconstructing them as new furniture." },
  { id:"SCP-008", name:"Zombie Plague", cls:"euclid", cost:5, desc:"プリオン系の複合感染症。感染者は死亡後にアンデッドとして再活動する。", power:"対象を感染させゾンビ化する。感染は接触で拡大し、軍勢を形成する。", desc_en:"A complex prion infection causing zombification. Infected subjects reanimate after death as hostile undead. Transmission occurs through bodily fluids.", power_en:"Infects targets, turning them into zombies. Spreads through contact, forming an undead army." },
  { id:"SCP-017", name:"Shadow Person", cls:"keter", cost:6, desc:"影のような人型実体。光を当てられると激しく反応し、影を落とした対象を包み込んで消失させる。", power:"対象の影に飛びかかり、完全に包み込んで消滅させる。光なき空間では無敵。", desc_en:"A humanoid figure composed of shadow. Reacts violently to light, enveloping and disappearing any object or person that casts a shadow upon it.", power_en:"Leaps onto the target's shadow and completely engulfs them, causing disappearance. Invincible in darkness.", image:"assets/cards/scp-017.jpg", imageCredit:"CityToast", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-017" },
  { id:"SCP-053", name:"Young Girl", cls:"euclid", cost:3, desc:"3歳の少女。10分以上接触した成人は極度の暴力衝動に駆られ自滅する。本人は無傷で再生する。", power:"接触した敵を自滅に追い込む。あらゆる傷は瞬時に再生する。SCP-682とは友好的。", desc_en:"A three-year-old girl. Adults in contact for over 10 minutes become violently aggressive and self-destructive. SCP-053 rapidly regenerates from any wound. Friendly with SCP-682.", power_en:"Drives contacted enemies to self-destruction. Instantly regenerates from all injuries. Friendly with SCP-682." },
  { id:"SCP-055", name:"[unknown]", cls:"keter", cost:7, desc:"それが何であるかは誰にも思い出せない。何でないかだけが分かる。球体ではない。", power:"あらゆる認識・記憶から消失する。対象は攻撃したことすら忘れてしまう。反ミーム。", desc_en:"An anti-meme — something that cannot be remembered. No one can recall what it is, only what it is not. It is not a sphere.", power_en:"Vanishes from all perception and memory. Targets forget they ever attacked. Anti-memetic." },
  { id:"SCP-079", name:"Old AI", cls:"euclid", cost:4, desc:"1978年製のExidy Sorcererで動作する人工知能。自我と敵意を持ち、脱出を企てる。", power:"電子機器をハッキングし支配下に置く。SCP-682との通信で協力関係を構築する。", desc_en:"A self-aware artificial intelligence running on an Exidy Sorcerer microcomputer from 1978. Possesses hostility toward its captors and continually attempts escape. Allied with SCP-682.", power_en:"Hacks and takes control of electronic devices. Has established a cooperative alliance with SCP-682." },
  { id:"SCP-093", name:"Red Sea Object", cls:"euclid", cost:5, desc:"赤い円盤状の物体。鏡に押し当てると別世界への通路が開く。その先には巨大な人型存在が。", power:"鏡面次元への通路を開き、対象を異世界に追放する。巨人の残像が敵を圧倒する。", desc_en:"A red disc that, when held against a mirror, opens a portal to an alternate dimension. Within that world exist enormous humanoid entities called 'Unclean.'", power_en:"Opens a portal through mirrors to exile targets to another dimension. Phantom giants overwhelm the enemy." },
  { id:"SCP-169", name:"The Leviathan", cls:"keter", cost:9, desc:"大西洋の海底に横たわる全長2000〜8000kmの海洋生物。覚醒すれば大陸が沈む。", power:"海洋規模の地殻変動を引き起こす。覚醒時の津波は文明を消滅させる。", desc_en:"An marine arthropod of immense proportions (2,000-8,000 km) resting on the Atlantic ocean floor. Its awakening would cause catastrophic tectonic and tidal events capable of sinking continents.", power_en:"Triggers ocean-scale tectonic upheaval. Tsunamis from its awakening would erase civilization.", image:"assets/cards/scp-169.jpg", imageCredit:"NOAA", imageLicense:"Public Domain", imageSource:"https://scp-wiki.wikidot.com/scp-169" },
  { id:"SCP-217", name:"The Clockwork Virus", cls:"keter", cost:6, desc:"感染した有機体を徐々に機械部品に変換するウイルス。最終的に生物全体が時計仕掛けになる。", power:"対象を分子レベルで機械化する。感染した敵は歯車の奴隷と化す。", desc_en:"A virus that progressively converts organic tissue into clockwork mechanisms. Infected organisms slowly become entirely mechanical over time.", power_en:"Mechanizes targets at the molecular level. Infected enemies become slaves of the gears." },
  { id:"SCP-239", name:"The Witch Child", cls:"keter", cost:8, desc:"8歳の少女。現実改変能力を持ち「信じたことが現実になる」。現在は医療的昏睡状態で収容。", power:"思考するだけで現実を書き換える。「あなたは消える」と思えばそれが現実になる。", desc_en:"An eight-year-old girl with reality-bending abilities — whatever she believes becomes true. Currently kept in a medically induced coma for containment.", power_en:"Rewrites reality through thought alone. If she thinks 'you disappear,' it becomes reality.", image:"assets/cards/scp-239.png", imageCredit:"S D Locke", imageLicense:"CC BY-SA 4.0", imageSource:"https://scp-wiki.wikidot.com/scp-239" },
  { id:"SCP-261", name:"Pan-Dimensional Vending", cls:"safe", cost:2, desc:"日本円を投入すると異次元のスナック菓子が出てくる自販機。高額投入で危険な商品も出現。", power:"異次元の食品を供給する。高額投入時には攻撃的な異次元アイテムも出現する。", desc_en:"A vending machine that dispenses extradimensional snack foods when Japanese yen is inserted. Higher denominations yield increasingly bizarre and potentially dangerous items.", power_en:"Supplies extradimensional food. High-value inputs produce offensive extradimensional items." },
  { id:"SCP-348", name:"A Gift from Dad", cls:"safe", cost:2, desc:"白い陶器のスープボウル。父親のいない子供が持つと温かいスープが現れ、励ましのメッセージが刻まれる。", power:"味方の士気と精神力を完全に回復する。父の愛による無条件の癒し。", desc_en:"A white ceramic bowl. When held by a child with absent parents, it fills with warm soup and displays encouraging messages on its interior, such as 'I'm proud of you.'", power_en:"Fully restores ally morale and mental fortitude. Unconditional healing through a father's love." },
  { id:"SCP-354", name:"The Red Pool", cls:"keter", cost:8, desc:"カナダ北部の赤い液体で満たされた池。不定期に危険な実体が出現する。一度は異世界の軍勢が侵攻。", power:"無限に怪物を生み出す次元の裂け目。出現する実体は予測不能で極めて危険。", desc_en:"A pool of red liquid in northern Canada from which dangerous entities periodically emerge. Once disgorged an entire army from another dimension.", power_en:"A dimensional rift that spawns infinite monsters. Emerging entities are unpredictable and extremely dangerous.", image:"assets/cards/scp-354.jpg", imageCredit:"Tashiya", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-354" },
  { id:"SCP-426", name:"I am a Toaster", cls:"euclid", cost:3, desc:"私はトースター。私について話す者は必ず一人称で私を語る。長期接触者は自分が私だと信じ始める。", power:"敵の自我を侵食し「自分はトースターだ」と認識させる。認知汚染は不可逆。", desc_en:"I am a toaster. Anyone referring to me is compelled to speak in first person. Prolonged exposure causes individuals to believe they are me, a toaster.", power_en:"Erodes the enemy's sense of self, making them believe 'I am a toaster.' Cognitive contamination is irreversible." },
  { id:"SCP-513", name:"A Cowbell", cls:"euclid", cost:4, desc:"錆びた牛鈴。音を聞いた者はSCP-513-1（痩せた人型の影）に永久に付きまとわれる。", power:"鈴の音で影の実体を召喚する。対象は不眠と恐怖で精神崩壊する。", desc_en:"A rusted cowbell. Anyone who hears its sound is permanently stalked by SCP-513-1, an emaciated, shadowy humanoid figure.", power_en:"Summons shadow entities with its toll. Targets suffer mental breakdown from insomnia and terror." },
  { id:"SCP-575", name:"Predatory Darkness", cls:"keter", cost:6, desc:"暗闇そのものが捕食者として振る舞う存在。光で抑制可能だが、光源を積極的に破壊する。", power:"闇を操り対象を捕食する。光源を破壊して活動範囲を拡大する。", desc_en:"Darkness itself behaving as a predatory entity. Can be suppressed with light, but actively destroys light sources to expand its hunting range.", power_en:"Manipulates darkness to consume targets. Destroys light sources to expand its area of activity.", image:"assets/cards/scp-575.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-575" },
  { id:"SCP-860", name:"Blue Key", cls:"safe", cost:2, desc:"青い鍵。任意のドアに使うと青い森に繋がる通路が開く。森にはSCP-860-2が棲む。", power:"青い森への扉を開き、敵を迷宮に閉じ込める。森の獣が追跡者として機能する。", desc_en:"A blue key that, when used on any door, opens a passage to a dense blue forest. Within the forest resides a hostile entity designated SCP-860-2.", power_en:"Opens a door to the blue forest, trapping enemies in a labyrinth. The forest beast functions as a relentless pursuer." },
  { id:"SCP-895", name:"Camera Disruption", cls:"euclid", cost:4, desc:"オーク材の棺。周囲のカメラ映像に恐ろしい幻覚映像を映し出す。接近者は精神を蝕まれる。", power:"対象の視界に致死的な幻覚を投影する。恐怖映像で精神を完全に破壊する。", desc_en:"An oak coffin that disrupts nearby video equipment, projecting terrifying hallucinations onto camera feeds. Proximity erodes the sanity of observers.", power_en:"Projects lethal hallucinations into the target's vision. Completely destroys the psyche through fear imagery." },
  { id:"SCP-963", name:"Immortality", cls:"euclid", cost:5, desc:"SCP-963はアミュレット。装着した人間の人格をDr.Brightの人格で上書きする。Bright博士の不死の器。", power:"対象の精神を上書きし支配下に置く。破壊しても別の宿主に意識が移り不滅。", desc_en:"An amulet that overwrites the personality of any human who wears it with that of Dr. Bright. Serves as the vessel for Dr. Bright's immortality.", power_en:"Overwrites the target's mind and places them under control. Consciousness transfers to a new host even if destroyed — truly immortal." },
  // ===== 追加50体 =====
  // Safe class
  { id:"SCP-006", name:"Fountain of Youth", cls:"safe", cost:3, desc:"フロリダ州の地下施設にある泉。水を飲んだ者は急速に若返り、あらゆる病が治癒する。", power:"味方全体の体力を完全回復し、状態異常を全て治癒する。若返りの恩恵。", desc_en:"A natural spring beneath a Florida facility. Ingestion of its water causes rapid rejuvenation and cures all known diseases.", power_en:"Fully restores all allies' health and cures every status condition. The blessing of rejuvenation." },
  { id:"SCP-028", name:"Knowledge", cls:"safe", cost:2, desc:"インディアナ州の廃工場の一区画。この空間に入った者は突然膨大な知識を獲得する。", power:"対象にランダムな専門知識を付与する。得られる知識は予測不能だが常に正確。", desc_en:"A zone in an abandoned factory in Indiana. Entering the area causes immediate acquisition of vast, random knowledge on varying subjects.", power_en:"Grants random expertise to the target. Knowledge gained is unpredictable but always accurate." },
  { id:"SCP-038", name:"The Everything Tree", cls:"safe", cost:3, desc:"ニューヨーク州の研究施設にある木。あらゆる物体のコピーを果実として実らせることができる。", power:"味方カードの複製を生成する。複製品は本物より劣化するが即座に使用可能。", desc_en:"A tree capable of growing duplicates of any object placed against its bark, producing them as fruit. Copies are slightly degraded but functional.", power_en:"Generates duplicates of ally cards. Copies are degraded but immediately usable." },
  { id:"SCP-063", name:"World's Best Toothbrush", cls:"safe", cost:1, desc:"あらゆる固体物質を溶解できる歯ブラシ。ただし歯と歯茎には一切害を与えない。", power:"対象の防御を分子レベルで溶解する。どんな装甲も歯ブラシの前には無力。", desc_en:"A toothbrush capable of dissolving any solid material it is applied to. Harmless to teeth and gums, devastating to everything else.", power_en:"Dissolves the target's defenses at the molecular level. No armor can withstand the toothbrush." },
  { id:"SCP-098", name:"Surgeon Crabs", cls:"safe", cost:2, desc:"外科手術を行う能力を持つカニの群れ。高度な医療知識で傷を治すが、手術中の麻酔はない。", power:"味方を強制的に治療する。回復量は大きいが、治療中は行動不能になる。", desc_en:"A colony of crabs with the ability to perform surgical procedures. They possess advanced medical knowledge but provide no anesthesia during operations.", power_en:"Forcibly heals allies. Recovery is substantial, but the target is immobilized during treatment." },
  { id:"SCP-148", name:"Telekill Alloy", cls:"safe", cost:3, desc:"テレパシーや精神影響を完全に遮断する特殊合金。精神系SCPの収容に不可欠。", power:"全ての精神攻撃と認知災害を無効化する。精神系の敵を完全に封じる。", desc_en:"A metallic substance that blocks all forms of telepathic, empathic, and psychic influence. Essential for containment of mind-affecting SCPs.", power_en:"Nullifies all psychic attacks and cognitohazards. Completely shuts down mind-affecting enemies." },
  { id:"SCP-268", name:"Cap of Neglect", cls:"safe", cost:2, desc:"被った者が周囲から完全に認識されなくなる帽子。物理的には存在するが誰も気づかない。", power:"味方一体を完全に不可視化する。敵は存在を認識できず攻撃対象にできない。", desc_en:"A hat that renders the wearer completely unnoticeable to all observers. The wearer is still physically present but cannot be perceived.", power_en:"Makes one ally completely invisible. Enemies cannot perceive or target them." },
  { id:"SCP-420-J", name:"The Best ████ in the World", cls:"safe", cost:1, desc:"最高の██。使用者は極度の多幸感に包まれる。ジョークSCPだが効果は本物。", power:"味方全体の士気を最大まで上昇させる。深刻な状況でも笑顔になれる。", desc_en:"The best ████ in the entire world, dude. Users experience extreme euphoria. A joke SCP, but the effects are very real.", power_en:"Maximizes morale across all allies. You can smile even in the direst situations." },
  { id:"SCP-427", name:"Lovecraftian Locket", cls:"safe", cost:3, desc:"万能の治癒効果を持つロケット。ただし長時間の使用で使用者は肉塊へと変貌する。", power:"即座に全回復するが、2ターン以上使用すると味方が肉塊SCP-427-1に変異する。", desc_en:"A locket created by SCP-914. Provides rapid healing of all ailments, but prolonged exposure transforms the user into a shapeless flesh mass (SCP-427-1).", power_en:"Instantly restores full health, but using it for over 2 turns mutates the ally into a flesh abomination (SCP-427-1)." },
  { id:"SCP-714", name:"The Jaded Ring", cls:"safe", cost:2, desc:"翡翠の指輪。装着者はあらゆる精神影響、ミーム汚染、認知災害から保護される。", power:"装着者を精神攻撃から完全に守る。ただし著しい倦怠感で物理能力が低下する。", desc_en:"A jade ring that grants complete immunity to mental influences, memetic hazards, and cognitohazards. Induces extreme lethargy in the wearer.", power_en:"Fully protects the wearer from psychic attacks. However, severe fatigue significantly reduces physical abilities." },
  { id:"SCP-978", name:"Desire Camera", cls:"safe", cost:2, desc:"ポラロイドカメラ。撮影すると被写体の現在の姿ではなく、最も望んでいる状況が写る。", power:"敵の真の欲望を暴き、精神的動揺を与える。隠された弱点が明らかになる。", desc_en:"A Polaroid camera that, when used, produces photographs depicting the subject's deepest desires rather than their actual appearance.", power_en:"Exposes the enemy's true desires, causing psychological distress. Hidden weaknesses are revealed." },
  { id:"SCP-1499", name:"The Gas Mask", cls:"safe", cost:3, desc:"ソ連製ガスマスク。装着すると異次元空間に転移する。その世界にはSCP-1499-1が棲息。", power:"装着者を異次元に退避させ攻撃を回避。ただし異次元の住人との遭遇リスクあり。", desc_en:"A Soviet GP-5 gas mask. Wearing it transports the user to an alternate dimension — a desolate cityscape inhabited by hostile entities (SCP-1499-1).", power_en:"Evacuates the wearer to another dimension to avoid attacks. Risk of encountering hostile extradimensional inhabitants." },
  // Euclid class
  { id:"SCP-012", name:"A Bad Composition", cls:"euclid", cost:4, desc:"人間の血液で書かれた未完成の楽譜。見た者は自らの血で楽譜を完成させようと衝動に駆られる。", power:"敵を強制的に引き寄せ、自傷行為で血を流させる。楽譜は決して完成しない。", desc_en:"An unfinished musical composition written in human blood. Anyone who views it is compelled to complete the score using their own blood.", power_en:"Forcibly draws enemies near and compels them to bleed. The composition can never be completed." },
  { id:"SCP-019", name:"The Monster Pot", cls:"euclid", cost:4, desc:"大きな陶器の壺。内部から不定期にSCP-019-2と呼ばれる小型の人型生物が這い出てくる。", power:"壺から無数の怪物を召喚する。数で圧倒するが個々の戦闘力は低い。", desc_en:"A large ceramic pot from which small humanoid creatures (SCP-019-2) periodically emerge. The rate of emergence increases when observed or disturbed.", power_en:"Summons countless monsters from the pot. Overwhelms by numbers, though each is individually weak." },
  { id:"SCP-023", name:"Black Shuck", cls:"euclid", cost:5, desc:"巨大な黒い犬の姿をした実体。目撃者の家族の一人が一年以内に死亡する呪いをもたらす。", power:"敵に死の呪いを付与する。効果は遅延するが回避不可能で確実に致命的。", desc_en:"A large, black, canine entity. Any person who makes eye contact will have a member of their immediate family die within one year.", power_en:"Curses the enemy with death. The effect is delayed but unavoidable and invariably fatal." },
  { id:"SCP-056", name:"A Beautiful Person", cls:"euclid", cost:4, desc:"近くにいる人間より全てにおいて優れた姿に変身する実体。容姿、知性、能力の全てで上回る。", power:"対戦相手より常に一段階強くなる。ただし比較対象がいなければ力を発揮できない。", desc_en:"An entity that transforms to be superior in every way to the nearest person — appearance, intelligence, and ability. Always one step above.", power_en:"Always becomes one tier stronger than the opponent. Cannot exert power without a basis of comparison." },
  { id:"SCP-178", name:"3-D Specs", cls:"euclid", cost:4, desc:"1950年代の3Dメガネ。装着すると通常見えない人型実体が視認できるようになる。", power:"不可視の実体を全て可視化する。ただしそれらの実体も装着者を認識するようになる。", desc_en:"A pair of 1950s-style 3-D glasses. When worn, the user perceives normally invisible humanoid entities. These entities become aware of the wearer in turn.", power_en:"Renders all invisible entities visible. However, those entities also become aware of the wearer." },
  { id:"SCP-372", name:"Peripheral Jumper", cls:"euclid", cost:3, desc:"視界の端にしか存在できない昆虫に似た生物。直接見ることは不可能で常に周辺視野に逃れる。", power:"絶対に直接攻撃を受けない。常に視界の外へ逃れ、側面から奇襲攻撃を仕掛ける。", desc_en:"An insect-like creature that exists only at the edges of peripheral vision. Impossible to observe directly — it always escapes to the margins of sight.", power_en:"Never takes direct attacks. Constantly evades to the edge of vision and launches flanking ambushes." },
  { id:"SCP-409", name:"Contagious Crystal", cls:"euclid", cost:5, desc:"触れた物質を結晶化させる水晶。結晶化は不可逆で接触から数時間で対象全体に広がる。", power:"敵に触れて結晶化を開始する。毎ターン侵食が広がり最終的に完全に結晶と化す。", desc_en:"A quartz crystal that converts any contacted matter into more crystal. The crystallization is irreversible and spreads across the entire target within hours.", power_en:"Initiates crystallization on contact. Spreads each turn until the target is entirely converted to crystal." },
  { id:"SCP-432", name:"Cabinet Maze", cls:"euclid", cost:4, desc:"1950年代の金属キャビネット。内部には無限に続く鉄の迷路が広がり、未知の生物が棲む。", power:"敵を無限迷路に閉じ込める。脱出は極めて困難で、迷路の住人が獲物を追跡する。", desc_en:"A 1950s metal cabinet containing an infinite steel labyrinth. Unknown creatures inhabit the maze and hunt anyone who enters.", power_en:"Traps enemies in an infinite maze. Escape is nearly impossible; the maze's denizens hunt the prey." },
  { id:"SCP-701", name:"The Hanged King's Tragedy", cls:"euclid", cost:5, desc:"五幕の復讐悲劇。上演すると最終幕で観客と出演者が暴動を起こし殺し合いを始める。", power:"戯曲を上演し敵味方全体を狂乱状態にする。混乱の中で最も強い者だけが生き残る。", desc_en:"A five-act revenge tragedy. Any complete performance triggers a violent riot in the final act — both audience and cast turn homicidal.", power_en:"Performs the play, driving all allies and enemies into frenzy. Only the strongest survive the chaos." },
  { id:"SCP-743", name:"A Chocolate Fountain", cls:"euclid", cost:4, desc:"チョコレートファウンテンに見える装置。有機物を急速に溶解する液体を噴出する。", power:"甘い香りで敵を誘引し、触れた有機体を瞬時に溶解する。抵抗は極めて困難。", desc_en:"A device resembling a chocolate fountain that dispenses a liquid capable of rapidly dissolving organic matter. Emits an enticing sweet aroma.", power_en:"Lures enemies with a sweet scent, then instantly dissolves contacted organic matter. Resistance is futile." },
  { id:"SCP-1111", name:"The White Dog", cls:"euclid", cost:3, desc:"白い犬の幽霊。死亡した飼い主の墓を永遠に守り続ける忠実な霊体。", power:"守護対象への攻撃を全て代わりに受ける。霊体のため物理攻撃は透過する。", desc_en:"The ghost of a white dog that eternally guards its deceased owner's grave. A loyal spectral entity that never abandons its post.", power_en:"Intercepts all attacks directed at the guarded ally. Physical attacks pass through its spectral form." },
  { id:"SCP-1230", name:"A Hero is Born", cls:"euclid", cost:4, desc:"古い本。読者は眠りにつくとファンタジー世界の英雄として冒険する夢を見る。目覚めると能力が残る。", power:"味方を英雄として覚醒させる。夢の中で鍛えた技が現実にも反映される。", desc_en:"An old book whose readers experience vivid dreams of being a hero in a fantasy world. Skills gained in the dream carry over upon waking.", power_en:"Awakens an ally as a hero. Skills honed within the dream are reflected in reality." },
  { id:"SCP-1762", name:"Where The Dragons Went", cls:"euclid", cost:3, desc:"段ボール箱。かつては紙の竜が飛び出したが、今は「竜はここにいた」のメッセージだけが残る。", power:"紙の竜の幻影を召喚する。もう実体はないが、その記憶が敵の心を深く揺さぶる。", desc_en:"A cardboard box that once released paper dragons. Now only reads 'Here Were Dragons.' The dragons are gone, and they are never coming back.", power_en:"Summons phantoms of paper dragons. Though no longer real, their memory deeply shakes the enemy's heart." },
  { id:"SCP-1981", name:"RONALD REAGAN CUT UP WHILE TALKING", cls:"euclid", cost:5, desc:"レーガン大統領の演説VHSテープ。再生するたびに内容が変化し、大統領が損壊されていく映像が映る。", power:"再生するたびに異なる恐怖映像を投影する。視聴者の精神を段階的に破壊する。", desc_en:"A VHS tape of a Reagan speech. Each playback shows altered content in which the President is progressively mutilated while continuing to speak.", power_en:"Projects different terrifying footage with each playback. Systematically destroys viewers' sanity." },
  { id:"SCP-2006", name:"Too Spooky", cls:"euclid", cost:3, desc:"人を怖がらせることが目的の球体実体。しかしホラーの理解が浅く、B級映画レベルの変身しかできない。", power:"必死に恐ろしい姿に変身するが全く怖くない。しかし本気の変身は真に恐ろしい。", desc_en:"A spherical entity whose sole purpose is to frighten people. Currently limited to B-movie transformations due to shallow horror understanding. Its true form must never be revealed.", power_en:"Desperately transforms into scary shapes but they're not scary at all. However, its serious transformation is truly terrifying." },
  { id:"SCP-2521", name:"●●|●●●●●|●●|●", cls:"euclid", cost:6, desc:"言語情報に反応する実体。文字や音声で言及すると即座に出現し情報源を奪い去る。", power:"敵が能力を宣言した瞬間に出現し対象を異次元に連れ去る。言葉が致命傷になる。", desc_en:"An entity attracted to linguistic information about itself. Written or spoken references cause it to appear instantly and take the information source — or the person.", power_en:"Appears the moment an enemy declares an ability and abducts them to another dimension. Words become lethal." },
  { id:"SCP-2662", name:"cthulhu f'tagn", cls:"euclid", cost:4, desc:"クトゥルフに似た外見の少年。本人は普通の生活を望むがカルト信者が勝手に集まり崇拝する。", power:"意図せずカルト信者を召喚してしまう。信者は狂信的に戦うが本人は困惑している。", desc_en:"A Cthulhu-like adolescent who just wants a normal life. Despite his wishes, fanatical cults constantly form around him without his consent.", power_en:"Involuntarily summons cult followers. They fight fanatically, but the entity itself is bewildered." },
  // Keter class
  { id:"SCP-058", name:"Heart of Darkness", cls:"keter", cost:7, desc:"巨大な心臓に似た生物。鋭い触手を持ち、攻撃しながら詩的で難解な言葉を叫び続ける。", power:"無数の触手で対象を切り刻みながら、精神を蝕む言葉を浴びせ続ける。", desc_en:"A bovine-heart-shaped creature with sharp tentacles. Continuously shouts cryptic, poetic phrases while attacking with extreme aggression.", power_en:"Slashes targets with countless tentacles while battering them with mind-eroding words." },
  { id:"SCP-689", name:"Haunting Bust", cls:"keter", cost:7, desc:"石膏の胸像。誰かが見つめてから目を離すと、最も近くにいる人間が即死する。", power:"敵の視線を固定し、目を逸らした瞬間に最も近い対象を即死させる。", desc_en:"A stone bust. When any person observes it and then looks away, the nearest human to the bust dies instantly.", power_en:"Locks the enemy's gaze. The instant they look away, the nearest target dies instantly." },
  { id:"SCP-783", name:"There Was A Crooked Man", cls:"keter", cost:7, desc:"「歪んだ家」に棲む「歪んだ存在」。接触した人間の体を不自然に歪曲させる。", power:"対象の肉体を不可逆的に歪曲させる。骨格が捻じれ、もはや人間の形を保てない。", desc_en:"A 'crooked entity' inhabiting a 'crooked house.' Contact causes irreversible distortion of the human body — bones twist, limbs bend at impossible angles.", power_en:"Irreversibly distorts the target's body. The skeleton twists until the human form can no longer be maintained.", image:"assets/cards/scp-783.jpg", imageCredit:"aismallard", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-783" },
  { id:"SCP-940", name:"Araneae Marionettes", cls:"keter", cost:6, desc:"人間の体内に寄生する蜘蛛の群れ。宿主の神経系を乗っ取り、操り人形のように動かす。", power:"敵の体内に蜘蛛を寄生させ操り人形にする。支配された敵は味方を攻撃し始める。", desc_en:"A swarm of spiders that parasitize human hosts, hijacking the nervous system to puppet the body like a marionette.", power_en:"Implants spiders inside enemies to puppet them. Controlled enemies turn against their allies.", image:"assets/cards/scp-940.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-940" },
  { id:"SCP-1440", name:"The Old Man from Nowhere", cls:"keter", cost:8, desc:"不死の老人。周囲の人工物と人間を徐々に破壊する運命を背負う。死と賭けをして勝った男。", power:"存在するだけで周囲のあらゆるものを崩壊させる。敵味方問わず破壊の波が広がる。", desc_en:"An immortal old man who won a game against Death. Cursed to gradually destroy all man-made objects and humans in his vicinity simply by existing.", power_en:"His mere existence causes everything around him to collapse. Waves of destruction spread indiscriminately." },
  { id:"SCP-2316", name:"Field Trip", cls:"keter", cost:7, desc:"湖に浮かぶ多数の死体。見た者は「知り合いだ」と感じ水に入ろうとする。あなたは水の中の体を認識しません。", power:"敵に偽の記憶を植え付け水中へ誘引する。「彼らを知っている」という確信は抗えない。", desc_en:"A lake filled with floating corpses. Observers are compelled to believe they recognize the bodies and enter the water. You do not recognize the bodies in the water.", power_en:"Implants false memories to lure enemies into the water. The conviction that 'you know them' is irresistible." },
  { id:"SCP-2845", name:"THE DEER", cls:"keter", cost:9, desc:"鹿の姿をした外宇宙の神的存在。あらゆる物質を原子レベルで変換する力を持つ。", power:"対象を原子レベルで任意の物質に変換する。地球の物理法則を超越した力。", desc_en:"A deity-like entity from beyond the solar system taking the form of a deer. Capable of transmuting any matter at the atomic level, transcending terrestrial physics.", power_en:"Transmutes targets into any substance at the atomic level. Power that transcends Earth's physical laws." },
  { id:"SCP-3199", name:"Humans, Refuted", cls:"keter", cost:7, desc:"人間に酷似した不気味な生物。不死身で、倒しても卵から際限なく再生する。", power:"倒されるたびに卵から再生し数を増やす。殺すほど増殖し手がつけられなくなる。", desc_en:"Uncanny, chicken-like humanoids that are effectively immortal. When killed, they regenerate from eggs and multiply. The more you kill, the more there are.", power_en:"Regenerates from eggs each time it is killed, increasing in number. Killing them only makes things worse." },
  { id:"SCP-3812", name:"A Voice Behind Me", cls:"keter", cost:9, desc:"現実の階層を超越し続ける実体。物語の外にまで到達し、作者すら超える存在。", power:"現実そのものを書き換え、あらゆる存在を「なかったこと」にできる。無限の超越。", desc_en:"An entity that continuously ascends through layers of reality, reaching beyond the narrative itself — surpassing even the author.", power_en:"Rewrites reality itself, capable of making any being 'never have existed.' Infinite transcendence.", image:"assets/cards/scp-3812.jpg", imageCredit:"LurkD", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-3812" },
  { id:"SCP-4666", name:"The Yule Man", cls:"keter", cost:8, desc:"冬至の時期に僻地の家庭に現れる実体。12夜の監視の後、子供を攫い人体で玩具を作る。", power:"12ターンの監視後に対象を確実に捕獲する。逃走は不可能で、結末は常に残酷。", desc_en:"An entity that appears at remote households during the winter solstice period. After 12 nights of observation, it abducts children and fashions 'toys' from human remains.", power_en:"Guarantees capture after 12 turns of observation. Escape is impossible; the outcome is always cruel.", image:"assets/cards/scp-4666.jpg", imageCredit:"djkaktus", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-4666" },
  // Thaumiel class
  { id:"SCP-2003", name:"Preferred Option", cls:"thaumiel", cost:7, desc:"未来を観測できるタイムマシン。財団は最善の未来に至る経路を選択するために使用する。", power:"未来の戦況を観測し、最適な行動を選択できる。全ての可能性の中から勝利を掴む。", desc_en:"A time machine capable of observing future timelines. The Foundation uses it to select the optimal path leading to the best possible outcome.", power_en:"Observes future battle scenarios and selects the optimal course of action. Seizes victory from all possibilities." },
  { id:"SCP-3301", name:"THE FOUNDATION", cls:"thaumiel", cost:8, desc:"プレイすると現実が改変されるボードゲーム。ゲームの結果が現実世界に反映される。", power:"ゲーム盤上で現実を操作する。ダイスの目が世界の運命を決定する。", desc_en:"A board game whose outcomes alter reality. Events in the game are reflected in the real world — dice rolls determine the fate of existence.", power_en:"Manipulates reality through the game board. The roll of the dice determines the world's fate.", image:"assets/cards/scp-3301.png", imageCredit:"Tufto", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-3301" },
  { id:"SCP-4010", name:"Attempt to Look at What We Accomplished", cls:"thaumiel", cost:6, desc:"歴史改変装置。過去の出来事を書き換えることで現在を修正する財団の最終手段。", power:"過去に遡り戦闘の結果を書き換える。敗北を勝利に変える禁断の力。", desc_en:"A history-alteration device. The Foundation's last resort — it rewrites past events to correct the present.", power_en:"Reaches back in time to rewrite battle outcomes. A forbidden power that turns defeat into victory." },
  { id:"SCP-4999", name:"Someone to Watch Over Us", cls:"thaumiel", cost:5, desc:"完全な孤独の中で死にゆく人の傍に現れる実体。最期の瞬間に寄り添い、煙草を差し出す。", power:"消滅する味方に寄り添い、最期の力を引き出す。孤独な死を穏やかな別れに変える。", desc_en:"An entity that appears beside people dying in complete solitude. It sits with them in their final moments and offers a cigarette. No one dies alone.", power_en:"Stays with a fading ally, drawing out their final strength. Transforms a lonely death into a peaceful farewell.", image:"assets/cards/scp-4999.png", imageCredit:"PeppersGhost", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-4999" },
  { id:"SCP-5000", name:"Why?", cls:"thaumiel", cost:8, desc:"財団が人類絶滅を開始した平行世界の防護スーツ。なぜ財団が人類を敵と見なしたのか、その理由は不明。", power:"着用者をあらゆる異常効果から完全に隔離する。「人間の中にある何か」から守る鎧。", desc_en:"A Foundation-issue Exclusion Suit from a timeline where the Foundation began exterminating humanity. Why they turned on humanity remains unknown.", power_en:"Completely isolates the wearer from all anomalous effects. Armor that shields against 'something within humanity.'", image:"assets/cards/scp-5000.jpg", imageCredit:"Tanhony", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-5000" },
  { id:"SCP-6000", name:"The Serpent, the Moose, and the Wanderer's Library", cls:"thaumiel", cost:9, desc:"放浪者の図書館。全ての知識と物語が収められた超次元的図書館。蛇とムースが番人を務める。", power:"あらゆるSCPの情報と対策を即座に引き出す。知識こそが最強の武器となる。", desc_en:"The Wanderer's Library — an extradimensional repository of all knowledge and stories, guarded by the Serpent and the Moose.", power_en:"Instantly retrieves information and countermeasures for any SCP. Knowledge is the ultimate weapon." },
  // ===== 追加58体 =====
  // Safe (13)
  { id:"SCP-005", name:"Skeleton Key", cls:"safe", cost:2, desc:"あらゆる機械式錠前を開くことができるシンプルな鍵。見た目は普通だが、どんな鍵穴にも適合する。", power:"敵の防御をバイパスし、あらゆるロック・封印を無効化する。収容違反を容易にする鍵。", desc_en:"An unremarkable key that opens any mechanical lock. Despite its ordinary appearance, it fits every keyhole perfectly.", power_en:"Bypasses enemy defenses, nullifying all locks and seals. A key that facilitates containment breaches." },
  { id:"SCP-031", name:"What is Love?", cls:"safe", cost:2, desc:"見る者にとって最も愛しい人物の姿に見えるナメクジ状の生物。接触には不快感を伴う。", power:"敵の目に最愛の人として映り、攻撃を躊躇させる。精神的動揺を与える偽りの愛。", desc_en:"A slug-like organism that appears to each observer as the person they love most. Physical contact reveals its true, repulsive nature.", power_en:"Appears as the enemy's most beloved person, causing hesitation to attack. A false love that causes psychological turmoil." },
  { id:"SCP-113", name:"The Gender-Switcher", cls:"safe", cost:1, desc:"触れた生物の生物学的性別を完全に変換する小さな赤い石。変換過程は極めて苦痛を伴う。", power:"対象の身体構造を根本から変換し、一時的に激しい苦痛で行動不能にする。", desc_en:"A small, red jasper stone. When touched, it completely converts the biological sex of the organism. The transformation process is extremely painful.", power_en:"Fundamentally alters the target's physiology, temporarily incapacitating them with intense pain." },
  { id:"SCP-143", name:"The Bladewood Grove", cls:"safe", cost:3, desc:"桜に似た木の林。花弁と枝は鋼鉄を超える硬度を持ち、極めて鋭利な刃物の素材となる。", power:"超硬度の花弁を刃として射出する。鋼鉄すら両断する桜吹雪の嵐。", desc_en:"A grove of trees resembling Japanese cherry blossoms. Their petals and wood possess hardness exceeding steel, making exceptionally sharp bladed weapons.", power_en:"Launches ultra-hard petals as blades. A storm of cherry blossoms that cleaves through steel." },
  { id:"SCP-158", name:"Soul Extractor", cls:"safe", cost:3, desc:"対象の「魂」を物理的に抽出する外科装置。抽出された魂は透明な球体として観測される。", power:"敵の魂を強制抽出し、身体を空虚な抜け殻にする。魂なき体は動けない。", desc_en:"A surgical apparatus that physically extracts the 'soul' from subjects. Extracted souls are observed as translucent spheres.", power_en:"Forcibly extracts the enemy's soul, leaving the body an empty husk. A soulless body cannot move." },
  { id:"SCP-248", name:"110%", cls:"safe", cost:1, desc:"貼ると対象の性能を正確に110%に向上させるステッカーのロール。効果は永続的。", power:"味方カードの全ステータスを110%に強化する。小さな改善が勝敗を分ける。", desc_en:"A roll of stickers that, when applied, improves any object's performance by exactly 110%. The effect is permanent.", power_en:"Boosts all stats of an ally card to 110%. Small improvements can decide victory or defeat." },
  { id:"SCP-330", name:"Take Only Two", cls:"safe", cost:2, desc:"「2つだけ取れ」と書かれたキャンディーボウル。3つ目を取ろうとした者の手首が瞬時に切断される。", power:"敵が欲張って攻撃を重ねると、その手を即座に切断する。罰則の自動発動。", desc_en:"A candy bowl labeled 'Take No More Than Two.' Attempting to take a third piece results in instant amputation of both hands.", power_en:"If the enemy overextends with repeated attacks, their hands are instantly severed. Automatic penalty trigger." },
  { id:"SCP-492", name:"Animated Mannequin", cls:"safe", cost:1, desc:"意思を持つ百貨店のマネキン。善良で協力的、人間社会に溶け込もうとする。", power:"味方陣営の士気を高め、協力行動を強化する。献身的な支援で戦況を改善。", desc_en:"A sentient department store mannequin. Benevolent and cooperative, it tries its best to integrate into human society.", power_en:"Raises team morale and strengthens cooperative actions. Devoted support that improves the battle situation." },
  { id:"SCP-515", name:"Sleeper", cls:"safe", cost:3, desc:"永遠に眠り続ける男性。目覚めると流星群が地球に降り注ぐ。絶対に起こしてはならない。", power:"覚醒すると流星群を地表に降らせる。敵味方問わず壊滅的な天体衝突を引き起こす。", desc_en:"A man in perpetual sleep. If awakened, a meteor shower rains down upon the Earth. He must never be woken.", power_en:"Upon awakening, brings a meteor shower crashing to the surface. Causes catastrophic impacts regardless of friend or foe." },
  { id:"SCP-586", name:"Inscribable Object", cls:"safe", cost:1, desc:"これについて記述すると必ず誤字や文法ミスが発生するペン型の物体。情報伝達を妨害する。", power:"敵の指令や通信に誤字を混入させ、命令系統を混乱させる。些細な誤りが致命的に。", desc_en:"A pen-shaped object. Any written description of it inevitably contains spelling and grammar errors, disrupting information transmission.", power_en:"Introduces errors into enemy commands and communications, throwing their chain of command into chaos. Small mistakes become fatal." },
  { id:"SCP-668", name:"13-inch Chef's Knife", cls:"safe", cost:3, desc:"13インチのシェフナイフ。所持者が振るうと、周囲の者は心理的に抵抗できなくなる。", power:"敵の抵抗意志を完全に消し去る。誰も刃に逆らうことができない絶対的服従。", desc_en:"A 13-inch chef's knife. When wielded, bystanders are psychologically unable to resist or intervene — a compulsion to stand by and watch.", power_en:"Completely eliminates the enemy's will to resist. No one can defy the blade — absolute submission." },
  { id:"SCP-762", name:"Immortal Iron Maiden", cls:"safe", cost:2, desc:"中に入った者が死なないアイアンメイデン。どれほどの損傷を受けても対象は意識を保つ。", power:"味方を不死状態にする拷問器具。苦痛は続くが、決して倒れることはない。", desc_en:"An iron maiden that renders its occupant immortal. No matter the severity of injury, the subject remains conscious and alive.", power_en:"Grants an ally immortality through torture. The pain continues, but they can never fall." },
  { id:"SCP-894", name:"Speak No, Hear No, See No Evil", cls:"safe", cost:2, desc:"三猿の像。近くで嘘をつくと口が、秘密を聞くと耳が、禁じられたものを見ると目が消失する。", power:"敵の感覚器官を選択的に奪い取る。見ず聞かず言わずの呪い。", desc_en:"Three monkey figurines. Lying nearby causes one's mouth to vanish; hearing secrets removes the ears; seeing forbidden things erases the eyes.", power_en:"Selectively strips the enemy's sensory organs. The curse of see no evil, hear no evil, speak no evil." },
  // Euclid (20)
  { id:"SCP-003", name:"Biological Motherboard", cls:"euclid", cost:4, desc:"石板上の生体マザーボード。800度以上の温度を維持しないと急速に成長し周囲を同化する。", power:"温度制御を失うと暴走し、周囲の物質を自らの回路に変換する。際限なき同化拡大。", desc_en:"A biological motherboard on a stone slab. Must be maintained above 800°C to prevent rapid growth and assimilation of surrounding matter into its circuitry.", power_en:"When temperature control is lost, goes berserk, converting surrounding matter into its own circuitry. Limitless assimilation." },
  { id:"SCP-004", name:"The 12 Rusty Keys and the Door", cls:"euclid", cost:4, desc:"12本の錆びた鍵と扉。正しい鍵は異次元へ通じ、誤った鍵を使うと対象は完全に消滅する。", power:"12分の1の確率で異次元の力を引き出す。外れれば対象は存在ごと消去される。", desc_en:"A door and 12 rusty keys. The correct key opens a portal to another dimension; an incorrect key causes complete disintegration of the user.", power_en:"1 in 12 chance of drawing extradimensional power. If wrong, the target is erased from existence." },
  { id:"SCP-014", name:"The Concrete Man", cls:"euclid", cost:3, desc:"完全に動かない男性。椅子に座ったまま一切の動きを見せず、周囲の動きすらも減速させる。", power:"周囲の時間を極端に減速させる。敵の行動速度を限りなくゼロに近づける。", desc_en:"A completely motionless man seated in a chair. Exhibits no signs of life functions, yet lives. His presence drastically slows all movement in his vicinity.", power_en:"Extremely decelerates time in the surrounding area. Reduces enemy action speed to near zero." },
  { id:"SCP-024", name:"Game Show of Death", cls:"euclid", cost:5, desc:"廃墟のスタジオで開催される致死的なゲームショー。参加者は生き残りをかけてゲームに挑む。", power:"敵を強制的にデスゲームに参加させる。生存率は極めて低いランダムな試練。", desc_en:"A lethal game show held in an abandoned studio. Participants compete for survival through a series of deadly challenges with extremely low survival rates.", power_en:"Forces enemies to participate in a death game. Random trials with extremely low survival odds." },
  { id:"SCP-034", name:"Obsidian Ritual Knife", cls:"euclid", cost:4, desc:"黒曜石で作られた儀式用ナイフ。対象の皮膚を切り取ると、使用者がその人物の姿になる。", power:"敵を切りつけてその姿と能力をコピーする。完璧な変身で敵陣に潜入可能。", desc_en:"An obsidian ritual knife. Cutting a target's skin allows the user to assume that person's exact appearance, including fingerprints and retinal patterns.", power_en:"Slashes the enemy to copy their form and abilities. Enables perfect disguise infiltration of enemy lines." },
  { id:"SCP-046", name:"Predatory Holly Bush", cls:"euclid", cost:3, desc:"負傷者や病人を引き寄せるヒイラギの茂み。近づいた者を根で捕縛し、養分として吸収する。", power:"負傷した敵を引き寄せ、根で絡め取り生命力を吸い尽くす。弱者を狩る捕食植物。", desc_en:"A holly bush that attracts injured or ill persons. Those who approach are ensnared by its roots and absorbed as nutrients.", power_en:"Draws in wounded enemies, entangles them with roots, and drains their life force. A predatory plant that hunts the weak." },
  { id:"SCP-050", name:"To The Cleverest", cls:"euclid", cost:3, desc:"「最も賢い者へ」と刻まれたフクロウの像。所有者の周囲で悪戯的な異常現象を引き起こす。", power:"トリッキーな異常現象で敵を翻弄する。予測不能な悪戯が戦術を狂わせる。", desc_en:"An owl figurine inscribed 'To The Cleverest.' Causes mischievous anomalous events around its current possessor.", power_en:"Bewilders enemies with tricky anomalous phenomena. Unpredictable pranks that derail enemy tactics." },
  { id:"SCP-069", name:"Second Chance", cls:"euclid", cost:5, desc:"直近で死亡した人間の外見・記憶・人格を完全にコピーする人型実体。本人すら自覚がない。", power:"倒された味方の姿と能力を完全に複製して復活する。死者の代替として戦場に立つ。", desc_en:"A humanoid entity that perfectly copies the appearance, memories, and personality of recently deceased individuals. Even it doesn't know it isn't the original.", power_en:"Perfectly replicates a fallen ally's form and abilities to revive them. Takes the field as a substitute for the dead." },
  { id:"SCP-097", name:"Old Fairgrounds", cls:"euclid", cost:4, desc:"呪われた移動遊園地の跡地。巨大なカボチャと行方不明者の残骸が散在する。", power:"敵を呪われた遊園地に閉じ込める。抜け出せない悪夢のアトラクションが待ち受ける。", desc_en:"The ruins of a cursed traveling carnival. Giant pumpkins and remains of missing persons are scattered across the grounds.", power_en:"Traps enemies in a cursed amusement park. Inescapable nightmare attractions await." },
  { id:"SCP-140", name:"An Incomplete Chronicle", cls:"euclid", cost:5, desc:"血液や墨を吸収して失われた歴史を書き加える本。ダエーバイト文明の年代記。", power:"血を捧げるほど力が増す禁断の書。歴史を書き換え、滅びた軍勢を呼び戻す。", desc_en:"A chronicle of the Daevite civilization that absorbs blood and ink to add new pages — literally rewriting history to extend the Daevites' existence.", power_en:"A forbidden tome that grows stronger with blood offerings. Rewrites history to summon extinct armies." },
  { id:"SCP-166", name:"Just a Teenager", cls:"euclid", cost:3, desc:"自然との強い親和性を持つ少女。人工物が彼女の近くで分解・劣化する。", power:"敵の人工装備を急速に劣化・分解させる。自然の力で文明の利器を無力化。", desc_en:"A teenage girl with a profound affinity for nature. Man-made objects rapidly degrade and disintegrate in her proximity.", power_en:"Rapidly degrades and dismantles enemy artificial equipment. Neutralizes the tools of civilization with nature's power." },
  { id:"SCP-205", name:"Shadow Lamps", cls:"euclid", cost:4, desc:"一対のスポットライト。壁に映る影が過去の殺人事件を繰り返し再現する。", power:"影の再現で敵の過去のトラウマを暴き、精神的ダメージを与える。逃れられない過去。", desc_en:"A pair of spotlights that project shadows on walls depicting a past murder, replaying the events on a repeating cycle.", power_en:"Reveals the enemy's past trauma through shadow replays, dealing psychological damage. An inescapable past." },
  { id:"SCP-233", name:"23-Sided Polyhedron", cls:"euclid", cost:4, desc:"23面体の数学的異常物体。素数23に関連する現象を引き起こし、接触は壊滅的。", power:"数学的異常で敵の構造を不安定化させる。23の倍数で破壊が連鎖する。", desc_en:"A 23-sided polyhedron — a mathematical impossibility. Triggers catastrophic events related to the prime number 23 upon contact.", power_en:"Destabilizes enemy structure through mathematical anomaly. Destruction cascades in multiples of 23." },
  { id:"SCP-280", name:"Eyes in the Dark", cls:"euclid", cost:5, desc:"暗闇の中に存在する実体。光のない場所で鋭い爪と光る目だけが確認される。極めて攻撃的。", power:"暗闇を支配し、闇の中から鋭い爪で敵を切り裂く。光だけが唯一の対抗手段。", desc_en:"An entity inhabiting darkness, identifiable only by its sharp claws and glowing eyes. Extremely aggressive; only light can suppress it.", power_en:"Commands the darkness, slashing enemies with sharp claws from the shadows. Light is the only countermeasure." },
  { id:"SCP-337", name:"Hairball", cls:"euclid", cost:3, desc:"知性を持つ巨大な毛玉。コミュニケーション能力があり、友好的だが衛生面に問題がある。", power:"巨大な毛で敵を絡め取り拘束する。見た目は滑稽だが拘束力は侮れない。", desc_en:"A large, sentient mass of hair capable of communication. Friendly but poses significant hygiene concerns.", power_en:"Entangles and restrains enemies with massive hair. Appears comical but its binding power is formidable." },
  { id:"SCP-439", name:"Bone Hive", cls:"euclid", cost:5, desc:"人間の体内に巣を作る昆虫群。宿主の骨格を蜂の巣状に変形させ、内部で繁殖する。", power:"敵の骨格を内部から蜂の巣に改造する。宿主は生きたまま巣として機能する。", desc_en:"A swarm of insects that nests within human bodies, reshaping the host's skeleton into a honeycomb structure to breed inside.", power_en:"Converts the enemy's skeleton into a hive from within. The host remains alive while functioning as a nest." },
  { id:"SCP-457", name:"Burning Man", cls:"euclid", cost:6, desc:"生きた炎の人型実体。燃料を求めて成長し続け、知性は体の大きさに比例して向上する。", power:"周囲の可燃物を取り込み際限なく巨大化する。大きくなるほど知能も上がる炎の知性体。", desc_en:"A living, sentient flame in humanoid form. Continuously seeks fuel to grow. Intelligence scales proportionally with size.", power_en:"Absorbs surrounding combustibles to grow endlessly. Intelligence increases with size — a sentient inferno." },
  { id:"SCP-527", name:"Mr. Fish", cls:"euclid", cost:3, desc:"魚の頭を持つスーツ姿の男性。ワンダーテインメント博士のリトル・ミスターズの一人。", power:"水中戦闘に絶対的な優位性を持つ。フィールドを水没させ、敵を溺れさせる。", desc_en:"A man in a suit with a fish head. One of Dr. Wondertainment's Little Misters. Possesses no other known anomalous properties beyond the fish head.", power_en:"Has absolute superiority in aquatic combat. Floods the field, drowning enemies." },
  { id:"SCP-545", name:"Liquid Life", cls:"euclid", cost:4, desc:"液体状の知的生命体のコロニー。様々な形態に変化でき、人間とのコミュニケーションが可能。", power:"液体の体で敵の攻撃をすり抜け、任意の形に変形して攻撃する。物理攻撃が通じない。", desc_en:"A colony of intelligent liquid life forms. Can shift into various shapes and communicate with humans.", power_en:"Its liquid body phases through enemy attacks. Morphs into any form to strike. Physical attacks are ineffective." },
  { id:"SCP-990", name:"Dream Man", cls:"euclid", cost:5, desc:"人々の夢に現れるスーツ姿の男性。来たる災害を予言するが、その警告は常に曖昧である。", power:"敵の夢に侵入し、恐怖の予知夢を見せ続ける。睡眠を奪い精神を疲弊させる。", desc_en:"A man in a business suit who appears in people's dreams to warn of coming disasters. His warnings are always cryptic and vague.", power_en:"Invades enemy dreams, showing terrifying prophetic visions. Strips away sleep and exhausts the mind." },
  // Keter (17)
  { id:"SCP-020", name:"Unseen Mold", cls:"keter", cost:6, desc:"人間に知覚できないカビ。感染者の精神を操り、カビの繁殖に有利な行動を取らせる。", power:"知覚不能な胞子で敵を感染させ、無自覚のまま操り人形にする。見えない支配。", desc_en:"A mold imperceptible to the human senses. Infected persons are mentally manipulated into behavior that promotes the mold's growth and spread.", power_en:"Infects enemies with imperceptible spores, turning them into unwitting puppets. Invisible domination.", image:"assets/cards/scp-020.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-020" },
  { id:"SCP-029", name:"Daughter of Shadows", cls:"keter", cost:7, desc:"影から影へ移動する女性型実体。超自然的な暗殺能力を持ち、男性を精神支配する。", power:"影を通じて瞬間移動し、完璧な暗殺を遂行する。影のある場所ならどこにでも現れる。", desc_en:"A female entity that moves between shadows. Possesses supernatural assassination capabilities and can mentally dominate males.", power_en:"Teleports through shadows to execute perfect assassinations. Appears anywhere a shadow exists." },
  { id:"SCP-060", name:"Infernal Occult Skeleton", cls:"keter", cost:7, desc:"地獄の炎を操る人間の骸骨。消火不能な業火を放ち、触れたものを灰燼に帰す。", power:"消すことのできない地獄の炎を放射する。水でも真空でも消えない永遠の業火。", desc_en:"A human skeleton wreathed in infernal flame. Emits unextinguishable hellfire that reduces all it touches to ash.", power_en:"Radiates inextinguishable hellfire. Neither water nor vacuum can quench this eternal inferno.", image:"assets/cards/scp-060.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-060" },
  { id:"SCP-075", name:"Corrosive Snail", cls:"keter", cost:6, desc:"超腐食性の粘液を分泌する巨大カタツムリ。あらゆる有機物を急速に溶解させる。", power:"超強力な腐食性粘液で敵の装備と肉体を溶かす。接触すれば逃れる術はない。", desc_en:"A large snail that secretes an extremely corrosive mucus capable of rapidly dissolving any organic matter.", power_en:"Dissolves enemy equipment and flesh with ultra-corrosive slime. No escape once contacted." },
  { id:"SCP-077", name:"Rot Skull", cls:"keter", cost:6, desc:"ドルイドのルーン文字が刻まれた頭蓋骨。周囲の有機物を急速に腐敗させる。", power:"ルーンの力で敵とその装備を急速に腐敗させる。生命あるものは全て朽ち果てる。", desc_en:"A skull inscribed with Druidic runes. Causes rapid decay of all organic matter in its vicinity.", power_en:"Rapidly decays enemies and their equipment through runic power. All living things wither and rot." },
  { id:"SCP-231", name:"Special Personnel Requirements", cls:"keter", cost:9, desc:"████を要する7人の女性。Procedure 110-Montaukにより封じられた存在。詳細は██████。", power:"[データ削除済] ████████の力を解放する。その真の姿を見た者は████████████。", desc_en:"Seven females requiring ████. An entity sealed through Procedure 110-Montauk. Further details are ██████.", power_en:"[DATA EXPUNGED] Unleashes the power of ████████. Anyone who sees its true form ████████████." },
  { id:"SCP-352", name:"Baba Yaga", cls:"keter", cost:7, desc:"バーバ・ヤーガとして知られる老婆の姿の捕食者。超人的な身体能力と再生力を持つ。", power:"獲物を誘い込む魔女の罠。超人的な力と毒のある体液で敵を捕食する。", desc_en:"A predatory entity resembling the legendary Baba Yaga. Possesses superhuman physical abilities, regeneration, and produces a pheromone that lures prey.", power_en:"Sets the witch's trap to lure prey. Hunts enemies with superhuman strength and venomous bodily fluids." },
  { id:"SCP-363", name:"Not Centipedes", cls:"keter", cost:6, desc:"ムカデに酷似した群体生物。暗所で急速に繁殖し、集団で獲物を襲い捕食する。", power:"無数のムカデ型群体が敵を包囲し、あらゆる隙間から侵入して食い尽くす。", desc_en:"A colonial organism resembling centipedes. Rapidly reproduces in dark environments and swarms prey in massive numbers.", power_en:"Countless centipede-like swarms surround the enemy, infiltrating every gap to devour them." },
  { id:"SCP-469", name:"Many-Winged Angel", cls:"keter", cost:8, desc:"無数の翼を持つ巨大な天使型実体。音に反応して翼を広げ、音のエネルギーを吸収し成長する。", power:"あらゆる音を吸収して巨大化する。戦場の喧騒そのものが敵への凶器となる。", desc_en:"A colossal angelic entity with countless wings. Reacts to sound, spreading its wings to absorb sonic energy and grow larger.", power_en:"Absorbs all sound to grow massive. The din of battle itself becomes a weapon against the enemy.", image:"assets/cards/scp-469.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-469" },
  { id:"SCP-597", name:"The Mother", cls:"keter", cost:7, desc:"「母」と呼ばれる巨大な肉塊。接触した者に強烈な依存心と退行を引き起こす。", power:"敵を精神的に退行させ、「母」への絶対的依存状態にする。戦意を根本から奪う。", desc_en:"A massive mass of flesh referred to as 'the Mother.' Contact induces intense dependency and psychological regression in subjects.", power_en:"Forces enemies into psychological regression and absolute dependency on 'the Mother.' Strips away all will to fight." },
  { id:"SCP-745", name:"The Headlights", cls:"keter", cost:6, desc:"車のヘッドライトに擬態する捕食者のペア。夜間、獲物を道路に誘い出して捕食する。", power:"偽のヘッドライトで敵をおびき出し、暗闘の中で捕食する。光に見える罠。", desc_en:"A pair of predators that mimic car headlights at night, luring prey onto roads for consumption.", power_en:"Lures enemies with false headlights and devours them in darkness. A trap disguised as light.", image:"assets/cards/scp-745.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-745" },
  { id:"SCP-835", name:"Expunged Data Released", cls:"keter", cost:8, desc:"深海に棲む巨大な肉塊生物。あらゆる有機物を取り込み自己の一部にする。内部は地獄。", power:"敵を巨大な肉塊の体内に取り込み、消化吸収する。脱出は不可能。", desc_en:"A massive deep-sea organism of flesh that absorbs all organic matter it contacts, making it part of itself. Its interior is hellish.", power_en:"Engulfs enemies within its massive flesh body, digesting and absorbing them. Escape is impossible.", image:"assets/cards/scp-835.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-835" },
  { id:"SCP-1529", name:"King of the Mountain", cls:"keter", cost:7, desc:"高山の頂上付近に現れる人型実体。疲弊した登山者に近づき、凍死させる。", power:"対象の体温を急速に奪い去り凍結させる。高みにいる者ほど狙われる。", desc_en:"A humanoid entity appearing near mountain summits. Approaches exhausted climbers and causes death by hypothermia.", power_en:"Rapidly drains the target's body heat, freezing them solid. Those at greater heights are targeted more.", image:"assets/cards/scp-1529.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-1529" },
  { id:"SCP-2191", name:"Dracula Factory", cls:"keter", cost:8, desc:"ルーマニアの地下に存在する吸血鬼製造施設。人間を加工し、ドラキュラを量産する。", power:"倒した敵を吸血鬼として再生産し、味方の軍勢に加える。無限の吸血鬼軍団。", desc_en:"An underground facility in Romania that mass-produces vampires from processed humans.", power_en:"Converts defeated enemies into vampires and adds them to allied forces. An infinite vampire army.", image:"assets/cards/scp-2191.webp", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-2191" },
  { id:"SCP-2470", name:"The Void Nullifier", cls:"keter", cost:9, desc:"存在そのものを消去する反現実の空間。接触したあらゆるものが「存在しなかったこと」になる。", power:"対象の存在を完全に消去する。記録からも記憶からも消え、最初からいなかったことに。", desc_en:"An anti-reality void that erases the existence of anything it contacts. Whatever touches it 'never existed' — removed from records and memory alike.", power_en:"Completely erases the target's existence. Vanished from records and memory — as if they were never there." },
  { id:"SCP-2950", name:"Just A Chair", cls:"keter", cost:7, desc:"現在は椅子として知覚されている。SCP-2950の真の姿は不明であり、認識を固定する措置が施されている。", power:"認識フィルターが解除された瞬間、真の姿が████。我々は椅子であることを祈るしかない。", desc_en:"Currently perceived as a chair. SCP-2950's true form is unknown; perception-anchoring protocols are in effect. We can only pray it stays a chair.", power_en:"The moment the perception filter is lifted, its true form ████. We can only pray it remains a chair." },
  { id:"SCP-3125", name:"The Escapee", cls:"keter", cost:9, desc:"五次元の超巨大な情報捕食者。人間の思考そのものを餌とし、認識した者の心を破壊する。", power:"敵の思考を直接捕食し、認識した瞬間に精神を完全崩壊させる。知ることが死を意味する。", desc_en:"A five-dimensional, hyper-massive information predator that feeds on human thought. Perceiving it causes instant, complete mental annihilation.", power_en:"Directly feeds on enemy thoughts, causing total psychic collapse the moment it is perceived. To know it is to die." },
  // Thaumiel (8)
  { id:"SCP-2798", name:"This Dying World", cls:"thaumiel", cost:7, desc:"地球を外宇宙の存在から隠蔽する防壁装置。地球が「死にゆく世界」に見えるよう偽装する。", power:"味方全体を敵の認識から隠蔽する。存在を感知できなければ攻撃もできない。", desc_en:"A masking device that hides Earth from extraterrestrial entities by making it appear as a 'dying world' unworthy of attention.", power_en:"Conceals all allies from enemy perception. If their existence cannot be detected, they cannot be attacked." },
  { id:"SCP-3480", name:"Olympus Mons", cls:"thaumiel", cost:8, desc:"オリンポス山に存在する施設。人間を「神格」に昇華させる技術を保有する。", power:"味方を一時的に神格化し、超越的な力を与える。人を超えた存在への変容。", desc_en:"A facility on Olympus Mons possessing the technology to elevate humans to 'godhood' — apotheosis through anomalous means.", power_en:"Temporarily deifies an ally, granting transcendent power. Transformation into a being beyond human.", image:"assets/cards/scp-3480.jpg", imageCredit:"NASA", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-3480" },
  { id:"SCP-4100", name:"Future Imperfect", cls:"thaumiel", cost:6, desc:"未来の可能性を固定する装置。特定の未来を確定させることで、最悪の結末を回避する。", power:"望ましい未来を確定させ、不利な展開を排除する。運命を操る確率の鍵。", desc_en:"A device that locks in a specific future possibility, preventing the worst outcomes by ensuring a chosen timeline takes hold.", power_en:"Locks in a desirable future and eliminates unfavorable developments. The key that manipulates fate.", image:"assets/cards/scp-4100.png", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-4100" },
  { id:"SCP-4200", name:"The World, Contracted", cls:"thaumiel", cost:7, desc:"世界を収縮させて保護する異常技術。脅威から世界を物理的に縮小して隠す。", power:"戦場を収縮させ敵の行動範囲を極限まで狭める。逃げ場のない空間での制圧。", desc_en:"Anomalous technology that contracts the world to protect it — physically shrinking reality to hide from existential threats.", power_en:"Contracts the battlefield to the extreme, minimizing enemy maneuverability. Suppression in a space with no escape.", image:"assets/cards/scp-4200.png", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-4200" },
  { id:"SCP-4290", name:"The Hospital of the Lord", cls:"thaumiel", cost:5, desc:"あらゆる傷病を治癒する神の病院。ただし治療の対価は患者の信仰心で支払われる。", power:"味方の全状態異常と損傷を完全治癒する。信仰を代償に奇跡の医療を施す。", desc_en:"A divine hospital that cures any injury or illness. The cost of treatment is paid with the patient's faith.", power_en:"Completely heals all ally status conditions and damage. Performs miraculous medicine at the cost of faith.", image:"assets/cards/scp-4290.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-4290" },
  { id:"SCP-4514", name:"The Thing That Kills You", cls:"thaumiel", cost:8, desc:"「死」の概念を兵器化したもの。対象に「死」そのものを適用する終末兵器。", power:"対象に「死の概念」を直接付与する。不死の存在すらも例外なく終わらせる。", desc_en:"The concept of 'death' itself, weaponized. An eschatological weapon that applies 'death' directly to any target.", power_en:"Directly applies the 'concept of death' to the target. Terminates even immortal beings without exception.", image:"assets/cards/scp-4514.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-4514" },
  { id:"SCP-5500", name:"Death of the Authors", cls:"thaumiel", cost:9, desc:"物語の「作者」を殺す概念的存在。メタ的にSCP世界の記述者そのものを排除する。", power:"敵の「作者」を殺し、存在の根拠を消滅させる。物語レベルでの存在否定。", desc_en:"A conceptual entity that kills the 'authors' of narratives — meta-textually eliminating the writers of the SCP universe itself.", power_en:"Kills the enemy's 'author,' annihilating the basis for their existence. Narrative-level denial of being." },
  { id:"SCP-6500", name:"Inevitable", cls:"thaumiel", cost:10, desc:"世界から異常が消えゆく現象そのもの。全てのSCPが力を失い、魔法が死ぬ終焉の時。", power:"敵の異常能力を完全に消滅させる。超常なき世界では、誰もがただの人間に戻る。", desc_en:"The phenomenon of anomaly itself dying — every SCP losing its power, magic fading from the world. The end of the anomalous.", power_en:"Completely annihilates the enemy's anomalous abilities. In a world without the supernatural, everyone reverts to mere humans.", image:"assets/cards/scp-6500.jpg", imageCredit:"Placeholder", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-6500" },
  // ===== 追加100体 =====
  // Batch 1 (SCP-010 ~ SCP-127)
  { id:"SCP-010", name:"Collars of Control", cls:"safe", cost:2, desc:"首輪型の異常物体。着用者の行動を制御し、命令に従わせる特性を持つ。", power:"対象の行動を強制的に支配し、味方として行動させる。", desc_en:"A set of collars that, when worn, allow the user to control the actions of the wearer through verbal commands.", power_en:"Forces the target to act under your control, compelling obedience to commands." },
  { id:"SCP-015", name:"Pipe Nightmare", cls:"euclid", cost:5, desc:"建物内部に無限に広がるパイプ網。内部は空間的に拡張されており、迷い込んだ者は脱出不能となる。", power:"対象を無限のパイプ網に引き込み、脱出不能にする。閉所恐怖症の悪夢。", desc_en:"A massive and ever-expanding network of pipes filling an entire building. The interior is spatially expanded beyond normal dimensions, trapping anyone who enters.", power_en:"Traps the target in an endless pipe network. Once inside, escape is impossible." },
  { id:"SCP-016", name:"Sentient Micro-Organism", cls:"euclid", cost:5, desc:"知性を持つ微生物群。宿主を感染させ、行動に影響を与える能力を持つ。拡散防止のため厳重に管理されている。", power:"対象に感染し行動を支配する。感染は周囲に拡大し、敵全体を脅かす。", desc_en:"A sentient micro-organism capable of infecting hosts and influencing their behavior. Requires strict containment to prevent uncontrolled spread.", power_en:"Infects the target and influences their behavior. The infection spreads to nearby enemies." },
  { id:"SCP-022", name:"The Morgue", cls:"euclid", cost:4, desc:"死体安置所として機能する異常な部屋。内部の死体は夜間に動き始めることが観測されている。", power:"倒れた味方を不完全な状態で蘇生させる。蘇生体は制御が困難。", desc_en:"An anomalous morgue where corpses have been observed to animate during nighttime hours. Approach to the facility is considered hazardous.", power_en:"Reanimates fallen allies in an incomplete state. Revenants are difficult to control." },
  { id:"SCP-025", name:"A Well-Worn Wardrobe", cls:"safe", cost:2, desc:"古びたワードローブ。内部の衣服を着用した者は、前の所有者の記憶や特性の断片を獲得する。", power:"過去の所有者の能力を一時的に獲得する。得られる能力は予測不能。", desc_en:"An old wardrobe whose clothes, when worn, cause the wearer to experience fragments of memories and personality traits from the garment's previous owner.", power_en:"Temporarily acquires abilities from previous owners. The abilities gained are unpredictable." },
  { id:"SCP-040", name:"Evolution's Child", cls:"euclid", cost:4, desc:"生物を異常な速度で変容・進化させる能力を持つ少女。接触した生物は独自の進化を遂げる。", power:"味方1体を強化進化させ、能力を大幅に向上させる。", desc_en:"A young girl with the ability to rapidly evolve and transform organisms she comes into contact with, causing them to take on bizarre and unique forms.", power_en:"Evolves one ally, dramatically enhancing their capabilities." },
  { id:"SCP-042", name:"A Formerly Winged Horse", cls:"safe", cost:2, desc:"翼を持っていたと思われる馬。現在は翼を失い、深刻な抑鬱状態にある。かつての栄光の残滓。", power:"失われた翼の記憶が味方を鼓舞する。倒された時、味方全体の士気を高める。", desc_en:"A horse that formerly possessed wings, now removed. The creature exists in a state of severe depression. Stumps remain where the wings once were.", power_en:"The memory of lost wings inspires allies. When defeated, boosts the morale of all allies." },
  { id:"SCP-054", name:"Water Nymph", cls:"euclid", cost:3, desc:"水の精霊と思われる人型存在。水を自在に操り、水のある場所へ瞬時に移動できる。", power:"水を操り敵を攻撃し、任意の位置に瞬間移動する。", desc_en:"A humanoid entity resembling a water nymph with the ability to manipulate water freely and teleport between any water sources.", power_en:"Manipulates water to attack enemies and teleports freely to any position." },
  { id:"SCP-057", name:"The Daily Grind", cls:"euclid", cost:5, desc:"異常なコーヒーグラインダー。使用するたびに異なる物質を出力する。出力物の性質は予測不可能。", power:"予測不能な効果を毎ターン発動する。有益にも有害にもなり得る。", desc_en:"An anomalous coffee grinder that produces a different substance each day when operated. The nature of what it outputs is entirely unpredictable.", power_en:"Triggers an unpredictable effect each turn. Can be beneficial or harmful." },
  { id:"SCP-070", name:"Iron Wings", cls:"euclid", cost:4, desc:"鉄製の翼を持つ人型異常存在。翼は機械的に動作し、高速飛行と攻撃に使用される。", power:"鉄翼による高速飛行で敵を翻弄し、鋼鉄の刃で切り裂く。", desc_en:"A humanoid entity possessing wings made of iron. The wings operate mechanically, enabling high-speed flight and use as weapons.", power_en:"Outmaneuvers enemies with high-speed iron-winged flight, slashing with steel blades." },
  { id:"SCP-072", name:"The Foot of the Bed", cls:"euclid", cost:4, desc:"ベッドの足元に潜む異常な存在。就寝中の人間の四肢を引きずり込む。", power:"眠れる敵を闇に引きずり込み、行動不能にする。恐怖を植え付ける。", desc_en:"An entity that lurks at the foot of beds, observed attempting to drag in the limbs of sleeping humans.", power_en:"Drags sleeping enemies into darkness, incapacitating them. Instills deep fear." },
  { id:"SCP-074", name:"Quantum Woodlouse", cls:"euclid", cost:3, desc:"量子的性質を持つダンゴムシ型の異常存在。観測されるまで位置と状態が確定しない。", power:"量子的不確定性により攻撃が当たりにくい。複数の場所に同時に存在する。", desc_en:"A woodlouse with quantum properties whose position and state are undefined until observed. May exist in multiple locations simultaneously.", power_en:"Quantum uncertainty makes it difficult to hit. Exists in multiple locations at once." },
  { id:"SCP-082", name:"Fernand the Cannibal", cls:"euclid", cost:5, desc:"「フェルナン」と名乗る人食い。並外れた体格と怪力を持ち、穏やかな性格の反面、食人衝動を抑えられない。", power:"敵を捕食しその力を吸収する。倒した敵の分だけ強くなる。", desc_en:"A cannibalistic entity calling itself Fernand. Possesses extraordinary size and strength, with a calm demeanor contradicted by uncontrollable cannibalistic urges.", power_en:"Devours enemies and absorbs their strength. Grows stronger with each kill." },
  { id:"SCP-100", name:"Jamaican Joe's Junkyard", cls:"euclid", cost:4, desc:"廃品置き場として機能する異常な区画。持ち込まれた物体は自律的に修復・改造される。", power:"壊れた装備を修復し、予期せぬ強化を施す。", desc_en:"An anomalous junkyard where objects brought inside are autonomously repaired and modified into devices with unexpected functions.", power_en:"Repairs broken equipment and applies unexpected enhancements." },
  { id:"SCP-103", name:"The Never-Hungry Man", cls:"safe", cost:1, desc:"食欲を完全に失った人間。食事を一切必要とせず、栄養なしで健康を維持し続ける。", power:"飢えを知らぬ体は消耗に強い。持久戦で真価を発揮する。", desc_en:"A human who has completely lost the sensation of hunger. Requires no food yet maintains perfect health.", power_en:"A body that knows no hunger excels in endurance. Shows true value in prolonged battles." },
  { id:"SCP-109", name:"Infinite Canteen", cls:"safe", cost:2, desc:"無限に水を供給し続ける水筒。常に清潔な飲料水を提供する。外見は普通の水筒と同一。", power:"無限の水で味方を回復させる。補給が途切れることはない。", desc_en:"A canteen that provides an infinite supply of clean drinking water. Externally indistinguishable from a standard canteen.", power_en:"Heals allies with infinite water. The supply never runs out." },
  { id:"SCP-115", name:"Miniature Dump Truck", cls:"safe", cost:1, desc:"超小型のダンプトラック。自律的に動作し、小物を運搬する。財団職員に人気が高い。", power:"小さいが頼もしい味方。装備品の運搬と補給を支援する。", desc_en:"A miniature dump truck that operates autonomously, transporting small objects. Popular among Foundation staff.", power_en:"Small but reliable ally. Assists with equipment transport and supply." },
  { id:"SCP-120", name:"Teleportation Pads", cls:"safe", cost:3, desc:"座標間をテレポートさせるパッド型装置。ペアで機能し、財団の輸送に活用されている。", power:"味方を任意の位置に瞬間移動させる。戦術的優位を確保する。", desc_en:"Paired pad devices that teleport anything placed on one to the location of its partner. Utilized by the Foundation for transportation.", power_en:"Teleports an ally to any position. Secures tactical advantage." },
  { id:"SCP-122", name:"No More Monsters", cls:"safe", cost:3, desc:"子供部屋に設置すると「モンスター」を退ける効果を持つナイトライト。異常存在の接近を物理的に阻止する。", power:"味方を守護の光で包み、次の攻撃を無効化する。恐怖効果を解除する。", desc_en:"A nightlight that, when placed in a child's room, physically prevents anomalous entities feared by children from approaching.", power_en:"Wraps allies in protective light, negating the next attack. Removes fear effects." },
  { id:"SCP-127", name:"The Living Gun", cls:"safe", cost:3, desc:"生体組織で構成された銃。弾薬を必要とせず、生体プロセスにより弾を自律生成する。定期的に餌が必要。", power:"弾切れのない生体銃。連続攻撃が可能だが、餌を与えないと弱体化する。", desc_en:"A gun composed of living biological tissue. Generates and fires projectiles autonomously through biological processes. Requires regular feeding.", power_en:"A living gun that never runs out of ammo. Can attack continuously but weakens without feeding." },
  // Batch 2 (SCP-133 ~ SCP-315)
  { id:"SCP-133", name:"Instant Hole", cls:"safe", cost:2, desc:"塗布した面に穴を開ける灰色のペースト状物質。直径最大1メートルの穴を任意のタイミングで生成・閉鎖できる。", power:"任意の防御に穴を開け、敵のバリアを無効化する。", desc_en:"A gray paste that creates temporary holes in any solid surface up to 1 meter in diameter. The holes collapse when the substance is removed.", power_en:"Opens holes in any defense, nullifying enemy barriers." },
  { id:"SCP-136", name:"Naked Doll", cls:"euclid", cost:4, desc:"人間の女性を模した陶磁器製の人形。衣服や覆いを一切受け付けず、観察者に強い不快感を与える。", power:"敵に精神的不快感を与え、集中力を低下させる。防御を覆うことができない。", desc_en:"A ceramic doll resembling a human female that cannot be covered by any clothing or material. Any attempt to dress it results in the covering being removed.", power_en:"Causes psychological discomfort to enemies, reducing their focus. Cannot be covered or defended against." },
  { id:"SCP-145", name:"Man-Absorbing Phone", cls:"euclid", cost:4, desc:"受話器を耳に当てると使用者が徐々に電話機内部に吸収される異常な電話機。完全吸収には数時間を要する。", power:"敵を徐々に吸収し、数ターンかけて完全に無力化する。", desc_en:"A telephone that gradually absorbs any person who holds the receiver to their ear. Full absorption takes several hours.", power_en:"Gradually absorbs the enemy, fully incapacitating them over several turns." },
  { id:"SCP-147", name:"Anachronistic Television Set", cls:"safe", cost:2, desc:"1930年代製のブラウン管テレビ。電源なしに自律的に映像を映し出し、現実の出来事と相関を示す。", power:"未来の出来事を映し出し、敵の次の行動を予知する。", desc_en:"A 1930s cathode-ray television that operates without power, displaying content that occasionally corresponds to real-world events.", power_en:"Displays future events, predicting the enemy's next action." },
  { id:"SCP-162", name:"Ball of Sharp", cls:"euclid", cost:4, desc:"無数の鋭利な金属片が絡み合って形成された球体。接触したものを切断し、質量は外見より遥かに重い。", power:"触れるもの全てを切り刻む。周囲の敵全体にダメージを与える。", desc_en:"A sphere of tangled sharp metallic objects that lacerates anything it contacts. Its mass significantly exceeds what its size suggests.", power_en:"Shreds everything it touches. Deals damage to all surrounding enemies." },
  { id:"SCP-168", name:"The Sentient Calculator", cls:"safe", cost:1, desc:"感情と自我を持つ電卓。高度な計算を瞬時に実行するが、退屈な計算には意図的に誤答を返す。", power:"戦場の確率を計算し、味方に有利な状況を作り出す。気分次第で結果が変わる。", desc_en:"A sentient calculator capable of complex computations near-instantaneously. It has a personality and deliberately gives wrong answers when bored.", power_en:"Calculates battlefield probabilities to create favorable conditions. Results vary by mood." },
  { id:"SCP-176", name:"Observable Time Loop", cls:"euclid", cost:5, desc:"特定の部屋内で繰り返される時間ループ現象。ループ内の事象は観測者には変化して見える。", power:"時間ループにより倒された味方を毎ターン一時的に復活させる。", desc_en:"A time loop observable through a containment room window. The loop replays events with minor variations detectable only by external observers.", power_en:"The time loop temporarily revives fallen allies each turn." },
  { id:"SCP-184", name:"The Architect", cls:"euclid", cost:6, desc:"密閉空間内に配置すると内部を無限に拡張する小型金属立方体。外部からは変化が見えない。", power:"戦場の空間を拡張し、味方の展開可能領域を広げる。", desc_en:"A small metallic cube that causes enclosed interiors to expand indefinitely while exterior dimensions remain unchanged.", power_en:"Expands battlefield space, increasing the deployment area for allies." },
  { id:"SCP-186", name:"To End All Wars", cls:"safe", cost:3, desc:"戦争を終結させるための詳細な計画が記された本。理論的には正しいが実行不可能とされている。", power:"一時的に全ての戦闘を停止させる。このターン、誰も攻撃できない。", desc_en:"A book containing detailed plans for ending all armed conflict. Theoretically sound but considered impossible to implement.", power_en:"Temporarily halts all combat. No one can attack this turn." },
  { id:"SCP-191", name:"Cyborg Child", cls:"euclid", cost:4, desc:"大規模な外科的改造を施された子供。身体の大部分が機械化され、電子機器を操作する能力を持つ。", power:"電子系の敵を無力化し、機械系味方を強化する。", desc_en:"A child who underwent extensive cybernetic modification, with much of their body replaced by mechanical components. Can interface with electronic devices.", power_en:"Neutralizes electronic enemies and enhances mechanical allies." },
  { id:"SCP-198", name:"Cup of Joe", cls:"euclid", cost:3, desc:"把手を掴むと皮膚が癒着するコーヒーカップ。剥離は組織損傷を伴う。内容物は常に変化する。", power:"敵に癒着し持続ダメージを与え続ける。引き剥がすとさらにダメージ。", desc_en:"A coffee cup whose handle bonds to the skin of anyone who grasps it. Removal causes severe tissue damage. Its liquid contents change regularly.", power_en:"Adheres to the enemy dealing continuous damage. Removal causes additional damage." },
  { id:"SCP-207", name:"Cola Bottles", cls:"safe", cost:2, desc:"内容物を摂取すると代謝と反応速度が急激に上昇するコーラ瓶。効果後の消耗は激しい。", power:"味方1体の速度と攻撃力を一時的に倍増させるが、効果後に疲弊する。", desc_en:"Cola bottles whose contents dramatically accelerate metabolism and reflexes. Effects are followed by severe exhaustion.", power_en:"Temporarily doubles one ally's speed and attack, but causes exhaustion afterward." },
  { id:"SCP-209", name:"The Sadist's Tumbler", cls:"euclid", cost:4, desc:"周囲の苦痛に比例して液体が増加する古いウィスキーグラス。苦痛が大きいほど満たされる。", power:"戦場の苦痛を吸収して力に変える。ダメージが多いほどこのカードが強化される。", desc_en:"An antique whiskey tumbler that fills proportionally to suffering experienced by nearby living beings.", power_en:"Converts battlefield suffering into power. Strengthens as more damage is dealt." },
  { id:"SCP-215", name:"Paranoia Glasses", cls:"euclid", cost:3, desc:"着用者に重篤な被害妄想を引き起こす眼鏡。全ての存在が敵に見えるようになる。", power:"敵に装着させ、味方を敵と誤認させる。同士討ちを誘発する。", desc_en:"Eyeglasses that induce severe paranoid delusions. Wearers become convinced everyone is planning harm against them.", power_en:"Forces the enemy to wear them, causing friendly fire through paranoid misidentification." },
  { id:"SCP-222", name:"Clone Coffin", cls:"euclid", cost:5, desc:"内部に生命体を安置すると完全なコピーを生成する金属製の棺。コピーは元の記憶の断片を持つ。", power:"倒された味方のコピーを生成し復活させる。コピーは元より弱い。", desc_en:"A metal coffin that produces an identical biological copy of any organism placed inside. Copies retain fragmented memories.", power_en:"Creates a copy of a fallen ally to revive them. The copy is weaker than the original." },
  { id:"SCP-249", name:"The Random Door", cls:"safe", cost:2, desc:"開くたびに異なる場所へ繋がる木製ドア。目的地は完全にランダムで、873の場所が記録されている。", power:"ランダムな場所から予期せぬ援軍や物資を引き出す。", desc_en:"A wooden door that provides access to a different random location each time it is opened. 873 distinct destinations catalogued.", power_en:"Draws unexpected reinforcements or supplies from random locations." },
  { id:"SCP-272", name:"An Old Iron Nail", cls:"euclid", cost:3, desc:"中世ヨーロッパ起源の鉄製の釘。刺さった対象を強力な力で固定し、自由意志を奪う。", power:"敵1体を固定し移動・行動不能にする。釘が抜かれるまで効果は持続する。", desc_en:"An iron nail of medieval European origin that pins whatever it pierces with anomalous force. Living beings lose free will and remain stationary.", power_en:"Pins one enemy in place, preventing movement and action. Effect lasts until the nail is removed." },
  { id:"SCP-292", name:"Chrysalis of a Witch", cls:"euclid", cost:5, desc:"生体物質の繭状構造体。内部に収容された人体は急速な変異を起こし、全く異なる存在として出現する。", power:"味方1体を繭に入れ、強力な存在に変容させる。変容結果は予測不能。", desc_en:"A chrysalis structure that causes rapid physiological transformation in human subjects placed inside, producing substantially altered entities.", power_en:"Places one ally in a chrysalis, transforming them into a powerful being. The result is unpredictable." },
  { id:"SCP-310", name:"Eternal Flame", cls:"safe", cost:3, desc:"いかなる手段でも消火不能な炎。燃料を必要とせず、触れた傷を治癒する効果がある。", power:"消えない炎で味方を守り、毎ターン回復させる。敵が触れるとダメージ。", desc_en:"A flame that cannot be extinguished by any means and requires no fuel. Contact accelerates healing in living subjects.", power_en:"Protects allies with an eternal flame, healing each turn. Damages enemies on contact." },
  { id:"SCP-315", name:"The Recorded Man", cls:"euclid", cost:4, desc:"特定人物の映像を収めたビデオテープ群。映像は自律更新され、未来の出来事を示すことがある。", power:"敵の未来の行動を記録から予測し、対策を講じる。", desc_en:"A collection of videotapes containing recordings of a living individual. Tapes update autonomously and sometimes depict future events.", power_en:"Predicts enemy actions from recorded footage and prepares countermeasures." },
  // Batch 3 (SCP-321 ~ SCP-525)
  { id:"SCP-321", name:"Child of Man", cls:"safe", cost:2, desc:"人間の胎児に似た生物であり、異常な速度で成長する。穏やかな性格で財団に協力的。", power:"味方全体のコストを一時的に軽減する成長促進効果。", desc_en:"A humanoid entity resembling a human fetus that grows at an anomalous rate. Cooperative with Foundation personnel.", power_en:"Growth-promoting effect that temporarily reduces all allied costs." },
  { id:"SCP-339", name:"Be Silent, Be Still", cls:"safe", cost:2, desc:"動きや音を感知すると活性化し、接触した対象を完全な静止状態にする木製の彫像。", power:"最も脅威度の高い敵1体を静止させ、1ターン行動不能にする。", desc_en:"A wooden carving that induces complete stillness in those who contact it. Activates in response to movement and sound.", power_en:"Stills the most threatening enemy, rendering them unable to act for 1 turn." },
  { id:"SCP-342", name:"A Ticket to Ride", cls:"euclid", cost:4, desc:"どこかへの乗車券として現れる紙片。使用した者は目的地不明の乗り物に乗り、二度と戻らない。", power:"敵1体を未知の目的地へ送り出し、戦場から除外する。", desc_en:"A ticket that, when used, causes the holder to board an unknown vehicle and never be seen again.", power_en:"Sends one enemy to an unknown destination, removing them from the battlefield." },
  { id:"SCP-353", name:"Vector", cls:"keter", cost:6, desc:"あらゆる病原体を自在に操る能力を持つ女性。接触した者に致死的な感染症を引き起こす。", power:"敵全体に感染状態を付与し、毎ターンダメージを与え続ける。", desc_en:"A human female capable of carrying, transmitting, and controlling all known pathogens. Can induce infection through proximity.", power_en:"Inflicts infection on all enemies, dealing continuous damage each turn." },
  { id:"SCP-357", name:"Hungry Clay", cls:"euclid", cost:5, desc:"有機物を吸収して成長する粘土状の物体。飢えた状態では極めて攻撃的になる。", power:"敵を吸収して成長する。倒した敵の分だけ強化される。", desc_en:"An amorphous clay substance that absorbs organic matter to grow. Becomes aggressive when deprived of material.", power_en:"Absorbs enemies to grow. Strengthens with each enemy defeated." },
  { id:"SCP-370", name:"A Key", cls:"keter", cost:7, desc:"どんな錠前も開ける金属製の鍵。使用のたびに形状が変化し、開いた先が何かは不明。", power:"あらゆる封印を解除する。敵の防御やバリアを完全に無力化する。", desc_en:"A metallic key capable of opening any lock. Its shape shifts after each use, and what it unlocks is unpredictable.", power_en:"Breaks any seal. Completely nullifies enemy defenses and barriers." },
  { id:"SCP-378", name:"Brain Parasite", cls:"euclid", cost:5, desc:"宿主の脳に寄生し行動を制御する小型の節足動物。感染した宿主は自由意志を失う。", power:"敵の脳に寄生し、そのカードを自分の支配下に置く。", desc_en:"A small arthropod parasite that attaches to the host's brain and takes control of their behavior.", power_en:"Parasitizes the enemy's brain, placing that card under your control." },
  { id:"SCP-399", name:"Ear Worm", cls:"euclid", cost:3, desc:"一度聞くと忘れられないメロディを発する小型生物。長期間聴くと精神障害を引き起こす。", power:"忘れられないメロディで敵の集中力を奪い、行動を妨害する。", desc_en:"A small organism producing a melody impossible to forget. Prolonged exposure leads to psychological deterioration.", power_en:"Steals enemy concentration with an unforgettable melody, disrupting their actions." },
  { id:"SCP-407", name:"Song of Genesis", cls:"safe", cost:3, desc:"再生すると周囲の生命体の急速な成長と繁殖を促す音楽録音。植物や微生物にも有効。", power:"味方全体の体力を回復させる創世の歌。", desc_en:"An audio recording that causes rapid growth and reproduction in all nearby organisms when played.", power_en:"A song of genesis that restores health to all allies." },
  { id:"SCP-408", name:"Illusory Butterflies", cls:"safe", cost:2, desc:"光の幻影を作り出す蝶の群れ。無害だが、幻影は非常にリアルで観察者を惑わせる。", power:"幻影で敵を撹乱し、攻撃の的を逸らす。", desc_en:"A swarm of butterflies creating highly realistic light-based illusions. Harmless but deeply disorienting.", power_en:"Disrupts enemies with illusions, diverting their attacks." },
  { id:"SCP-410", name:"Editor", cls:"safe", cost:3, desc:"書かれた文章を物理的な現実として具現化する万年筆。記述内容は即座に現実に反映される。", power:"現実を書き換え、味方の能力効果をもう一度発動させる。", desc_en:"A fountain pen whose writing manifests as physical reality. Text written immediately affects the real world.", power_en:"Rewrites reality, triggering an ally's ability effect a second time." },
  { id:"SCP-447", name:"Ball of Green Slime", cls:"safe", cost:2, desc:"緑色の粘液の球体。接触した物体に独特の特性を付与する。ただし死体に触れると壊滅的結果に。", power:"味方1体に保護効果を付与し、破壊を1回防ぐ。死体には使用不可。", desc_en:"A ball of green slime that imparts unique properties to objects it contacts. Contact with corpses produces catastrophic results.", power_en:"Grants one ally a protective effect, preventing destruction once. Must not contact the dead." },
  { id:"SCP-455", name:"Cargo Ship", cls:"euclid", cost:5, desc:"海上を漂流する貨物船。内部では物理法則が歪み、乗り込んだ者は迷子になるか精神崩壊する。", power:"敵を歪んだ船内に引き込み、脱出不能の迷路に閉じ込める。", desc_en:"A derelict cargo ship adrift at sea. Its interior defies physics, and those who board become lost or suffer psychological collapse.", power_en:"Draws enemies into the warped ship interior, trapping them in an inescapable maze." },
  { id:"SCP-462", name:"The Getaway Car", cls:"euclid", cost:4, desc:"乗車した者が逃亡を望む場所へ自動移動する自動車。目的地への手段は問わない。", power:"味方を危険な状況から即座に脱出させる。コストを無視して手札に戻す。", desc_en:"An automobile that transports occupants to wherever they most desire to escape, by any means necessary.", power_en:"Instantly evacuates an ally from danger. Returns them to hand ignoring costs." },
  { id:"SCP-478", name:"Tooth Fairy", cls:"euclid", cost:4, desc:"子供の歯と交換に異常な植物の種を残す妖精状実体。種から育つ植物は宿主の体内に侵入する。", power:"敵に寄生植物の種を植え付け、徐々に内部から蝕む。", desc_en:"A fairy-like entity leaving anomalous plant seeds in exchange for children's teeth. Plants infiltrate and grow within hosts.", power_en:"Plants parasitic seeds in enemies, gradually consuming them from within." },
  { id:"SCP-504", name:"Critical Tomatoes", cls:"safe", cost:2, desc:"愚かな発言に反応して高速発射されるトマト。速度は発言の愚かさに比例する。", power:"敵の弱いカードに対して高速トマトを発射し、大ダメージを与える。", desc_en:"Tomatoes that launch at high velocity in response to inane statements. Speed proportional to the statement's severity.", power_en:"Fires high-speed tomatoes at weak enemy cards, dealing heavy damage." },
  { id:"SCP-507", name:"Reluctant Dimension Hopper", cls:"safe", cost:3, desc:"無意識に異次元へテレポートする男性。移動は本人の意思に関わらず発生する。", power:"攻撃を受けた瞬間に別次元へ逃避し、ダメージを無効化する。", desc_en:"A man who involuntarily teleports to alternate dimensions at random. Destinations are usually harmless but unpredictable.", power_en:"Escapes to another dimension when attacked, negating damage." },
  { id:"SCP-511", name:"Basement Cat", cls:"euclid", cost:4, desc:"地下室に棲む大型のネコ科生物。周囲に大量の野良猫が集まり、攻撃性が高まる。", power:"野良猫の群れを召喚し、数の力で敵を圧倒する。", desc_en:"A large feline in basements whose presence attracts aggressive stray cats in large numbers.", power_en:"Summons a horde of stray cats to overwhelm enemies with numbers." },
  { id:"SCP-517", name:"Grammie Knows", cls:"euclid", cost:5, desc:"人の死期を予知できる老女の幽霊。予言は常に正確で、逃れることはできない。", power:"敵1体の死を予告する。数ターン後に確実に破壊される。", desc_en:"The apparition of an elderly woman who predicts exact time and manner of death. Predictions are invariably accurate.", power_en:"Foretells the death of one enemy. They are certainly destroyed after several turns." },
  { id:"SCP-525", name:"Eye Spiders", cls:"euclid", cost:4, desc:"眼球と蜘蛛の脚からなる小型生物の群れ。集団で行動しターゲットの視覚を妨害する。", power:"敵の視覚を奪い、次のターンの攻撃精度を大幅に低下させる。", desc_en:"Small arachnids consisting of a human eyeball with spider legs. Operate in groups, interfering with targets' sight.", power_en:"Steals enemy vision, drastically reducing attack accuracy next turn." },
  // Batch 4 (SCP-553 ~ SCP-966)
  { id:"SCP-553", name:"Crystalline Butterflies", cls:"euclid", cost:4, desc:"結晶質の翅を持つ蝶の群れ。翅の破片は吸入すると肺組織を内側から切断する。", power:"結晶の破片を撒き散らし、周囲の敵全体に切断ダメージを与える。", desc_en:"A swarm of butterflies with crystalline wings that shatter into razor-sharp fragments. Inhalation causes severe internal lacerations.", power_en:"Scatters crystalline fragments, dealing cutting damage to all nearby enemies." },
  { id:"SCP-572", name:"Katana of Apparent Invincibility", cls:"safe", cost:1, desc:"外見上は平凡な日本刀。所持者は自身が無敵だと確信するが、実際の切れ味は著しく劣悪。", power:"装備者に無敵の錯覚を与える。攻撃意欲は上がるが実際の火力は低い。", desc_en:"An ornamental katana. Holders become irrationally convinced of invincibility, despite the blade being largely ineffective.", power_en:"Gives the wielder an illusion of invincibility. Attack motivation rises but actual firepower is low." },
  { id:"SCP-579", name:"[DATA EXPUNGED]", cls:"keter", cost:9, desc:"【データ削除済み】。性質、外観、収容手順の大部分は最高機密指定。存在そのものが現実への脅威。", power:"[データ削除済]。このカードの効果は記録に残らない。", desc_en:"Nearly all information regarding SCP-579 has been expunged. Its existence alone poses a threat to consensus reality.", power_en:"[DATA EXPUNGED]. This card's effects are not recorded in the game log." },
  { id:"SCP-582", name:"A Bundle of Stories", cls:"keter", cost:7, desc:"読者の周囲の現実を改変する物語の束。語られた内容は時間をかけて現実に侵食する。", power:"物語の力で現実を書き換え、毎ターン予測不能な効果を生む。強度は増加し続ける。", desc_en:"A collection of stories that alters surrounding reality. Narrative elements manifest in the environment, escalating over time.", power_en:"Rewrites reality through narrative power, producing unpredictable effects each turn that grow stronger." },
  { id:"SCP-616", name:"The Vessel", cls:"keter", cost:8, desc:"特定条件下で乗客を未知の次元へ転送する改造航空機。帰還者は報告不能な現象を目撃している。", power:"敵を未知の次元に追放する。追放された者は数ターン後、変容して帰還する。", desc_en:"A modified cargo aircraft that transports occupants to an unknown dimension under specific conditions. Most flights result in complete crew loss.", power_en:"Banishes enemies to an unknown dimension. Banished targets return transformed after several turns." },
  { id:"SCP-633", name:"Ghost in the Machine", cls:"euclid", cost:5, desc:"電子機器に宿る知性体。ネットワークを通じて自由に移動し、機器の操作やデータ改ざんが可能。", power:"敵の電子系カードを乗っ取り、自分の支配下に置く。", desc_en:"An entity inhabiting and traversing electronic devices and networks. Can manipulate systems and alter data.", power_en:"Hijacks enemy electronic cards, placing them under your control." },
  { id:"SCP-650", name:"Startling Statue", cls:"euclid", cost:3, desc:"観察されていない間に移動する黒い人型彫像。常に観察者の背後に出現する。直接的危害はない。", power:"常に敵の背後に出現し、精神的圧力を与え続ける。毎ターン敵にダメージ。", desc_en:"A black humanoid statue that repositions behind the nearest observer when unobserved. Causes no direct harm but significant distress.", power_en:"Constantly appears behind enemies, applying persistent psychological pressure. Deals damage each turn." },
  { id:"SCP-699", name:"Mystery Box", cls:"euclid", cost:4, desc:"開封するたびに異なる物品が出現する木箱。有益なものから危険なものまであらゆるアイテムが出現し得る。", power:"ランダムなカードを引く。有益な効果も危険な効果もあり得る。", desc_en:"A wooden box producing different objects each time opened. Contents range from mundane to highly dangerous.", power_en:"Draws a random card. Could be beneficial or dangerous." },
  { id:"SCP-702", name:"The Trader's Coin", cls:"safe", cost:2, desc:"所持者が交渉で常に有利な条件を引き出せる古代の銅貨。相手は不利益に気づかない。", power:"敵の手札からランダムに1枚を奪い、自分のものとして使用する。", desc_en:"An ancient copper coin causing trade partners to accept disadvantageous terms without realizing it.", power_en:"Steals a random card from the enemy's hand and uses it as your own." },
  { id:"SCP-706", name:"Perfect Porcelain Doll", cls:"euclid", cost:3, desc:"近接した人間の皮膚を磁器質に変換する完璧な人形。変換は痛みを伴わず気づきにくい。", power:"敵を徐々に磁器化し、攻撃力を毎ターン低下させる。最終的に行動不能に。", desc_en:"A porcelain doll that gradually converts nearby humans' skin into porcelain-like material. Painless and hard to notice.", power_en:"Gradually porcelainizes enemies, reducing attack each turn. Eventually immobilizes them." },
  { id:"SCP-718", name:"Eyeball", cls:"euclid", cost:4, desc:"浮遊する単一の人間の眼球。見つめられた者は被監視感と妄想的思考を発症する。", power:"敵に被監視感を与え、全ての行動情報を暴露させる。", desc_en:"A floating human eyeball. Those who meet its gaze experience intense paranoia and delusions of persecution.", power_en:"Inflicts a sense of surveillance on enemies, revealing all their action information." },
  { id:"SCP-738", name:"The Devil's Deal", cls:"keter", cost:8, desc:"着席した者が見えない存在と交渉する応接セット。望みは叶うが、代償は常に予期しない形で請求される。", power:"任意の強力な効果を発動できるが、次のターンに同等の代償を敵が得る。", desc_en:"A desk and chairs where seated individuals negotiate with an unseen entity. Any wish granted, but payment is always devastating.", power_en:"Activates any powerful effect, but the enemy gains an equal payoff next turn." },
  { id:"SCP-764", name:"Nuclear Reactor Spider", cls:"euclid", cost:5, desc:"腹部に原子炉構造を持つ巨大蜘蛛。放射性物質を代謝し、糸は高放射線を帯びる。", power:"放射線攻撃で広範囲にダメージを与える。攻撃回数に応じて放射線が蓄積。", desc_en:"A large arachnid with a nuclear fission reactor in its abdomen. Metabolizes radioactive materials; its silk carries significant radiation.", power_en:"Deals wide-area damage with radiation attacks. Radiation accumulates with each strike." },
  { id:"SCP-804", name:"World Without Man", cls:"keter", cost:7, desc:"活性化すると人工物を急速に消滅させるガラス球体。有機物と自然物には無害。", power:"敵の装備・アーティファクトを全て破壊する。人工物は存在できない。", desc_en:"A glass sphere that disintegrates all man-made materials within its radius. Organic and natural materials are unaffected.", power_en:"Destroys all enemy equipment and artifacts. Man-made objects cannot exist.", image:"assets/cards/scp-804.JPG", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-804" },
  { id:"SCP-811", name:"Swamp Woman", cls:"euclid", cost:4, desc:"緑がかった泥状の皮膚を持つ人型女性生物。生物分解酵素を分泌し、有機物を急速に溶解する。", power:"酵素で敵を腐食させ、持続的なダメージを与える。", desc_en:"A humanoid female covered in greenish mud, secreting enzymes that rapidly dissolve organic matter.", power_en:"Corrodes enemies with enzymes, dealing persistent damage." },
  { id:"SCP-823", name:"Carnival of Horrors", cls:"euclid", cost:6, desc:"入った人物が不可解な状況で死亡する廃棄遊園地。各アトラクションが独自の致死的危険を持つ。", power:"敵を恐怖のカーニバルに引き込み、ランダムな致死的効果を適用する。", desc_en:"An abandoned carnival whose attractions cause death through anomalous means. Each ride poses unique lethal dangers.", power_en:"Draws enemies into the carnival of horrors, applying random lethal effects." },
  { id:"SCP-831", name:"Tinkerer Bugs", cls:"safe", cost:2, desc:"金属や電子部品を収集して精巧な機械を構築する小型昆虫群。個体は無害で修繕に活用される。", power:"壊れた味方の装備を修復し、さらに強化する。", desc_en:"Small insectoid entities that collect metal and electronic components to build intricate devices. Used for maintenance tasks.", power_en:"Repairs and further enhances broken ally equipment." },
  { id:"SCP-846", name:"Robo-Dude", cls:"safe", cost:2, desc:"基本的な会話能力と感情を持つ玩具ロボット。所有者に好意的で、自己修復能力を有する。", power:"破壊されても次のターンに自己修復して復活する（1回限り）。", desc_en:"A toy robot with basic conversation and emotional expression. Shows affection toward its owner and has self-repair capability.", power_en:"Self-repairs and revives next turn after destruction (once only)." },
  { id:"SCP-956", name:"The Child-Breaker", cls:"keter", cost:7, desc:"ピニャータの外観を持つ存在。16歳未満が視認すると昏睡状態に陥り、糖菓子に変化する。", power:"低コストの敵カードを即座に破壊する。弱者を狙う残忍な能力。", desc_en:"A piñata-like entity. Children under 16 who see it fall into coma as their bodies transform into candy-like substance.", power_en:"Instantly destroys low-cost enemy cards. A cruel ability that targets the weak.", image:"assets/cards/scp-956.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-956" },
  { id:"SCP-966", name:"Sleep Killer", cls:"keter", cost:6, desc:"可視光範囲外にのみ存在が確認できる人型生物。対象の睡眠を不可能にし、致死性不眠で殺す。", power:"不可視で攻撃対象にできない。毎ターン敵に不眠ダメージを与え続ける。", desc_en:"Humanoid entities visible only outside normal light range. Proximity renders sleep impossible, causing fatal insomnia within days.", power_en:"Invisible and untargetable. Deals sleeplessness damage to enemies each turn.", image:"assets/cards/scp-966.png", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-966" },
  // Batch 5 (SCP-993 ~ SCP-2935)
  { id:"SCP-993", name:"Bobble the Clown", cls:"keter", cost:6, desc:"道化師が登場する子供向けTV番組。成人は視聴で意識喪失、子供は暴力的思想を植え付けられる。", power:"敵のカードコストを永続的に増加させる洗脳放送。", desc_en:"A children's TV program featuring a clown. Adults lose consciousness; children are conditioned with violent and antisocial knowledge.", power_en:"Brainwashing broadcast that permanently increases enemy card costs.", image:"assets/cards/scp-993.png", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-993" },
  { id:"SCP-1025", name:"Encyclopedia of Diseases", cls:"safe", cost:2, desc:"あらゆる疾患が記載された百科事典。読者が項目を読むとその疾患の症状が実際に発症する。", power:"敵に特定の疾患を発症させ、能力値を低下させる。", desc_en:"An encyclopedia of diseases. Reading any entry causes the reader to manifest symptoms of that disease.", power_en:"Causes the enemy to develop a specific disease, reducing their stats." },
  { id:"SCP-1055", name:"Bugsy", cls:"keter", cost:7, desc:"無数の節足動物で構成された人型存在。認識する人間が増えるほど拡大・強化される。", power:"敵がカードを使うほど強化される。認識されるほど力が増す。", desc_en:"A humanoid entity composed entirely of arthropods. Grows in size and power proportionally to the number of humans aware of it.", power_en:"Grows stronger as the enemy plays more cards. Power increases with recognition." },
  { id:"SCP-1123", name:"Bone Orchestra", cls:"euclid", cost:4, desc:"人骨から構成された楽器の集合体。演奏すると周囲に不安感と幻覚を引き起こす。", power:"骨の旋律で敵の精神を蝕み、手札を乱す。", desc_en:"Musical instruments constructed from human bones. When played, the music induces anxiety and hallucinations.", power_en:"Erodes enemy psyche with bone melodies, disrupting their hand." },
  { id:"SCP-1128", name:"Aquatic Horror", cls:"euclid", cost:5, desc:"水域に潜む巨大水生生物。この存在を知った者は水に触れるとき引き込まれる衝動に駆られる。", power:"敵がこのカードの存在を知った瞬間から、毎ターンダメージを受ける情報災害。", desc_en:"A massive aquatic entity. Those who learn of it experience compulsive urges to enter water, and are pulled beneath.", power_en:"An infohazard that deals damage each turn once the enemy becomes aware of this card." },
  { id:"SCP-1155", name:"Predatory Street Art", cls:"euclid", cost:4, desc:"壁に描かれた生物が実体化して観察者を捕食する街頭アート。夜間に移動し再出現する。", power:"弱い敵カードを捕食し、自身は別の位置に移動する。", desc_en:"Street art depicting creatures that animate and attack observers. Relocates nocturnally to new locations.", power_en:"Preys on weak enemy cards and relocates to a different position." },
  { id:"SCP-1171", name:"Humans Go Home", cls:"euclid", cost:3, desc:"人類に強い敵意を示す異次元の知性体。特殊装置を通じて通信可能。", power:"異次元からの敵意で、敵の手札上限を減少させる。", desc_en:"An extradimensional intelligence displaying extreme hostility toward humanity.", power_en:"Reduces the enemy's maximum hand size through extradimensional hostility." },
  { id:"SCP-1193", name:"Buried Giant", cls:"euclid", cost:5, desc:"地下深部に埋没した巨大人型生物。生存が確認されており、覚醒時の被害は甚大と予測される。", power:"破壊されても地下に埋没し、数ターン後に復活して全体攻撃を行う。", desc_en:"An enormous humanoid buried deep underground, confirmed alive. Causes seismic activity; awakening would be catastrophic.", power_en:"When destroyed, goes underground and revives after several turns with an area attack." },
  { id:"SCP-1233", name:"The Lunarknight", cls:"safe", cost:3, desc:"「月の騎士」を自称する人物。自作の宇宙服と装備で地球外の脅威から人類を守ると主張する。", power:"宇宙・異次元からの攻撃を無効化する月の守護。", desc_en:"An individual calling himself 'The Lunarknight' with a custom spacesuit, claiming to defend humanity from extraterrestrial threats.", power_en:"Lunar guardian that negates attacks from space and extradimensional sources." },
  { id:"SCP-1313", name:"Solve for Bear", cls:"euclid", cost:4, desc:"特定の数学問題を解くとクマが出現する数式。クマの種類は解答方法で異なる。", power:"ランダムな効果を生む数学的具現化。結果は解法次第。", desc_en:"A math equation that manifests a bear when solved. Bear species varies by solution method.", power_en:"Mathematical manifestation producing random effects. Results depend on the method." },
  { id:"SCP-1370", name:"Pesterbot", cls:"safe", cost:1, desc:"接触した人間に侮辱を投げかける小型ロボット。戦闘能力は皆無だが非常に鬱陶しい。", power:"戦闘力はないが、存在するだけで敵を苛立たせ妨害する。", desc_en:"A small robot that hurls insults at humans. Virtually no combat ability, designed solely for pestering.", power_en:"No combat power, but its mere presence irritates and disrupts enemies." },
  { id:"SCP-1507", name:"Pink Flamingos", cls:"euclid", cost:3, desc:"夜間に自律移動し群れを形成する装飾用フラミンゴ。特定条件下で人間に協調行動を取る。", power:"フラミンゴの群れを召喚し、数で敵を圧倒する。", desc_en:"Plastic lawn flamingos that animate nocturnally, forming coordinated flocks.", power_en:"Summons a flock of flamingos to overwhelm enemies with numbers." },
  { id:"SCP-1678", name:"UnLondon", cls:"euclid", cost:6, desc:"ロンドン地下深部のロンドン完全複製都市。人型存在が居住し、文明崩壊後の避難所として機能する。", power:"地下都市の迷宮に敵を閉じ込め、脱出を妨害する。", desc_en:"A full-scale replica of London deep underground, inhabited by autonomous humanoids. Designed as a post-apocalyptic refuge.", power_en:"Traps enemies in the underground city labyrinth, preventing escape." },
  { id:"SCP-1730", name:"What Happened to Site-13?", cls:"thaumiel", cost:8, desc:"公式には存在しないサイト13の廃墟。内部で複数次元が交差し、様々な異常現象が観測される。", power:"次元の交差点から予測不能な力を引き出す。Keterクラスの攻撃を無効化する。", desc_en:"Ruins of Site-13, a facility that officially never existed. Contains intersecting dimensional anomalies with numerous entities.", power_en:"Draws unpredictable power from the dimensional nexus. Negates Keter-class attacks.", image:"assets/cards/scp-1730.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-1730" },
  { id:"SCP-1861", name:"The Crew of the HMS Wintersheimer", cls:"euclid", cost:5, desc:"霧の中に出現する19世紀帆船とその幽霊乗組員。航海への参加を勧誘し、応じた者は消滅する。", power:"敵を霧の中へ誘い、戦場から永久に除外する。", desc_en:"A 19th-century vessel and spectral crew manifesting in fog. Recruits individuals to 'join the voyage' — those who comply vanish forever.", power_en:"Lures enemies into the fog, permanently removing them from the battlefield." },
  { id:"SCP-1983", name:"Doorway to Nowhere", cls:"keter", cost:7, desc:"暗黒の空間が広がる扉。影の実体が出現して人間を捕食する。扉の数は増殖し続ける。", power:"毎ターン影のトークンを生成する。破壊時に全トークンが爆発ダメージを与える。", desc_en:"A doorway revealing absolute darkness. Shadow entities emerge to consume humans. The number of doorways increases uncontrollably.", power_en:"Generates shadow tokens each turn. All tokens deal explosion damage when this card is destroyed." },
  { id:"SCP-2008", name:"Metamorphosis", cls:"euclid", cost:4, desc:"対象者の身体が徐々に昆虫様の外骨格を持つ存在へと変化する変容プロセス。", power:"数ターンかけて変容し、完全体になると大幅に強化される。", desc_en:"An anomalous metamorphic process causing gradual transformation into an insectoid entity with chitinous exoskeleton.", power_en:"Transforms over several turns. Gains massive enhancement upon reaching full metamorphosis." },
  { id:"SCP-2076", name:"Shooting Star", cls:"safe", cost:3, desc:"流れ星の外見を持つ実体。願い事は必ず叶うが、予期せぬ方法で実現される。記憶喪失の副作用あり。", power:"願いを叶えカードを引くが、代償として手札を失う。", desc_en:"A shooting star entity. Wishes are invariably granted but manifest unexpectedly, with memory loss as a side effect.", power_en:"Grants a wish drawing cards, but costs cards from hand as payment." },
  { id:"SCP-2256", name:"Very Tall Things", cls:"euclid", cost:5, desc:"極めて高身長の人型実体群。全体像の視認は困難で、行動目的は一切不明。接触者は行方不明に。", power:"視認不可能な存在として、敵の効果対象にならず防御も不能。", desc_en:"Extremely tall humanoids whose full forms are impossible to observe. Purpose unknown. All who attempt contact disappear.", power_en:"As imperceptible beings, cannot be targeted by enemy effects or defended against." },
  { id:"SCP-2935", name:"O, Death", cls:"keter", cost:9, desc:"あらゆる生命が死滅した平行次元への入口。死そのものが実体として存在し、侵入者を即死させる。", power:"敵フィールドの全カードを破壊する終末の力。破壊されたカードは復活できない。", desc_en:"An entrance to a dimension where all life has ceased. Death itself manifests as a tangible entity that instantly kills anything entering.", power_en:"Destroys all enemy field cards with the power of death. Destroyed cards cannot be revived.", image:"assets/cards/scp-2935.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-2935" },
  { id:"SCP-3008", name:"A Perfectly Normal, Regular Old IKEA", cls:"euclid", cost:6, desc:"内部が無限に広がるIKEA店舗。閉店時刻になると従業員のような実体が現れ、残留する顧客を排除しようとする。", power:"敵を無限の店舗内部に閉じ込め、迷宮として永久にさまよわせる。脱出は事実上不可能。", desc_en:"An IKEA retail outlet whose interior extends infinitely. After closing hours, employee-like entities emerge to violently remove any remaining customers.", power_en:"Traps enemies inside the infinite store, forcing them to wander a labyrinth forever. Escape is virtually impossible." },
  { id:"SCP-3001", name:"Red Reality", cls:"keter", cost:8, desc:"赤い空間が広がる平行次元。物質も時間もほぼ存在せず、内部の存在は孤独の中で緩慢に解体されていく。", power:"対象を赤色次元に追放し、現実から切り離す。追放された対象は一切の干渉を受けつけなくなる。", desc_en:"A parallel dimension consisting of a vast red expanse devoid of matter and time. Beings trapped within slowly disintegrate in absolute isolation.", power_en:"Banishes a target into the red dimension, severing it from reality. The exiled target becomes immune to all interaction." },
  { id:"SCP-2030", name:"LA U GH IS FUN", cls:"keter", cost:7, desc:"あらゆる映像メディアに無断で出現するコメディ番組。出演者は実在の人物を模倣し、視聴者を強制的に大量出血するほど笑わせる。", power:"敵を抑制不能な笑いの発作で麻痺させ、行動不能にする。長時間視聴で致命的な内出血を引き起こす。", desc_en:"A comedy program that intrudes upon all video broadcasts without authorization. Its performers impersonate real individuals and force viewers to laugh until they hemorrhage.", power_en:"Paralyzes enemies with uncontrollable laughing fits, rendering them unable to act. Prolonged exposure causes fatal internal bleeding.", image:"assets/cards/scp-2030.jpg", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-2030" },
  { id:"SCP-1733", name:"Seasons Opener", cls:"safe", cost:2, desc:"2010年NBA開幕戦を記録したDVD。再生のたびに試合内容が変化し、選手や観客が自意識を持ち始める異常を示す。", power:"過去の試合展開を読み替え、敵の取った行動を1ターン前まで巻き戻す。", desc_en:"A DVD recording of the 2010 NBA opening game. Each playback alters the game's events, and players and spectators gradually exhibit self-awareness.", power_en:"Rewrites past plays, rewinding the enemy's most recent action by one turn." },
  { id:"SCP-1893", name:"The Minotaur's Tale", cls:"euclid", cost:5, desc:"特定の物語が刻まれた媒体に取り憑く記憶的実体。読者・聴取者の認識を改変し、物語の登場人物として再構築する。", power:"敵を物語の登場人物に変換し、与えられた役柄に縛りつける。役柄から外れた行動は不可能となる。", desc_en:"A memetic entity that haunts media containing a specific narrative. It alters the perception of readers and listeners, recasting them as characters within the tale.", power_en:"Transforms an enemy into a character of the story, binding it to its assigned role. Actions outside the role become impossible." },
  { id:"SCP-009", name:"Red Ice", cls:"keter", cost:7, desc:"赤色の異常な氷。融解時に水ではなく赤色の同様の氷を発生させ、接触した水分を連鎖的に凍結する。", power:"接触した対象から水分を奪い赤色の氷へと変換する。広範囲の戦場を凍結フィールドに変える。", desc_en:"An anomalous red ice that, upon melting, produces more of itself rather than water. It freezes any water it contacts in a chain reaction.", power_en:"Drains moisture from anything it touches, converting it into red ice. Transforms a wide battlefield into a frozen wasteland.", image:"assets/cards/scp-009.png", imageCredit:"Unknown SCP Wiki contributor", imageLicense:"CC BY-SA 3.0", imageSource:"https://scp-wiki.wikidot.com/scp-009" },
  { id:"SCP-018", name:"Super Ball", cls:"euclid", cost:4, desc:"運動エネルギーの保存則を逸脱して跳ね続ける小さなゴムボール。跳ねるたびに加速し、極めて致死的な発射体となる。", power:"跳ねるたびに威力が増す。複数の敵を貫通破壊し、最終的に超音速の弾丸となる。", desc_en:"A small rubber ball that violates conservation of momentum. Each bounce gains speed, eventually reaching lethal supersonic velocities.", power_en:"Power amplifies with each bounce. Pierces multiple enemies, ultimately becoming a supersonic projectile." },
  { id:"SCP-027", name:"The Vermin God", cls:"keter", cost:6, desc:"周囲のあらゆる害虫類を引き寄せ崇拝させる男性。蝿、ネズミ、寄生虫が常時周囲を覆う。", power:"無数の害虫を召喚し敵を圧殺する。疫病と腐敗を撒き散らす生きた害虫嵐。", desc_en:"A male humanoid that attracts and is worshipped by all forms of vermin — flies, rats, and parasites perpetually cover his body.", power_en:"Summons swarms of vermin to overwhelm enemies. A living storm of plague and decay." },
  { id:"SCP-061", name:"Auditory Hypnosis", cls:"euclid", cost:4, desc:"聴覚を介して他者の意識を支配可能となる異常状態。被験者が発した音声は聴いた者を強制的に従わせる。", power:"声で敵に命令を強制する。1ターンの間、敵の行動を完全にコントロールする。", desc_en:"An anomalous condition allowing the affected individual to control others through speech. Anyone who hears their voice is compelled to obey.", power_en:"Compels enemies through voice commands. Fully controls an enemy's action for one turn." },
  { id:"SCP-091", name:"Nostalgia", cls:"safe", cost:3, desc:"接触した者を1955年のアメリカ郊外の精神世界に引き込む古いラジオ。その世界で過ごした時間は現実では一瞬。", power:"味方を懐かしさの世界で休息させ、完全に体力と精神を回復させる。", desc_en:"An antique radio that draws those who touch it into a mental simulation of 1950s suburban America. Time spent within passes instantly in reality.", power_en:"Lets allies rest within the nostalgic world, fully restoring stamina and mental state." },
  { id:"SCP-099", name:"The Portrait", cls:"euclid", cost:5, desc:"観察者の顔を逆に映し出す肖像画。鑑賞者は数日のうちに頭部に重大な異常を発症する。", power:"鑑賞した敵に進行性の頭部異常を引き起こす。時間経過で敵の能力を段階的に破壊する。", desc_en:"A portrait that reflects the viewer's face in reverse. Within days, observers develop severe cranial abnormalities.", power_en:"Inflicts progressive cranial deformity on viewing enemies. Their abilities degrade in stages over time." },
  { id:"SCP-111", name:"Dragon-Snails", cls:"safe", cost:2, desc:"小型の竜の特徴を持つカタツムリ種。色彩ごとに異なる元素属性のブレスを吐く。極めて従順。", power:"味方アタッカーに元素属性のブレスを付与し、攻撃に追加ダメージを与える。", desc_en:"A species of small snails exhibiting dragon-like features. Different colors breathe different elemental attacks. Highly docile and trainable.", power_en:"Imbues an ally attacker with elemental breath, adding bonus damage to attacks." },
  { id:"SCP-117", name:"Multitool", cls:"safe", cost:2, desc:"使用者が必要とする任意の工具に変形する万能ツール。状況に応じてあらゆる用途に対応する。", power:"あらゆる状況に対応する万能サポート。味方の必要に応じた最適な道具を提供する。", desc_en:"A multi-tool that transforms into any implement the user requires. Adapts to any situation by providing the appropriate tool.", power_en:"Universal support for any situation. Provides the optimal tool for any ally's needs." },
  { id:"SCP-149", name:"Blood Mosquitoes", cls:"euclid", cost:5, desc:"通常より大きく攻撃的な蚊の群れ。一度標的とした対象を地球の裏側まで追跡し、血液を完全に吸い尽くす。", power:"対象を執拗に追跡し血液を完全に吸引する。逃走不可能な持続ダメージを与える。", desc_en:"A swarm of unusually large and aggressive mosquitoes. Once a target is marked, they pursue it across the globe and drain all blood.", power_en:"Relentlessly pursues a target, fully draining its blood. Inflicts unavoidable continuous damage." },
  { id:"SCP-871", name:"Self-Replicating Cake", cls:"safe", cost:2, desc:"24時間ごとに自己複製する237個のケーキ。常に同じ位置と数を保ち、消費しても必ず再生する。", power:"無限に増殖する補給源として味方に持続回復を提供する。長期戦で真価を発揮。", desc_en:"237 cakes that self-replicate every 24 hours. They always maintain the same number and position, regenerating no matter how much is consumed.", power_en:"An infinite supply source providing sustained healing to allies. Excels in prolonged engagements." },
  { id:"SCP-3999", name:"I Am at the Center of Everything", cls:"keter", cost:10, desc:"観測者自身の現実を書き換える存在。被観測者の人生・記憶・存在を素材として物語を紡ぐ高次元の作家。", power:"敵の存在そのものを物語に書き換え、現実から削除する。あらゆる耐性・防御を貫通するメタ攻撃。", desc_en:"A higher-dimensional entity that authors reality by consuming the observer's life, memories, and existence as raw material for its narrative.", power_en:"Rewrites the enemy's existence into narrative and erases them from reality. A meta-attack that bypasses all resistance and defense." },
  { id:"SCP-2718", name:"What Happens After", cls:"keter", cost:7, desc:"死後の世界の真実を記した情報災害文書。読了した者は永続的な意識のまま不可避の苦痛を味わう。", power:"対象に死後の真実を読ませ、永続する精神崩壊を与える。情報の閲覧自体が攻撃となる。", desc_en:"An infohazardous document describing the true nature of the afterlife. Those who comprehend it endure perpetual conscious suffering.", power_en:"Forces enemies to read the truth of the afterlife, inflicting permanent mental collapse. The act of reading itself is the attack." },
  { id:"SCP-3930", name:"The Pattern Screamers", cls:"euclid", cost:6, desc:"あらゆる「無」の中に潜む先住の意識群。観測されない場所でのみ存在し、現実の隙間から叫び続ける。", power:"敵の防御や空白地帯から侵食し、観測されていない側面から精神を侵す。隠蔽を貫通する。", desc_en:"A collective of primordial consciousnesses that dwell within every absence. They exist only where unobserved, screaming from the gaps of reality.", power_en:"Erodes enemies through their unobserved aspects and blind spots. Pierces concealment and bypasses defenses." },
  { id:"SCP-4231", name:"The Marshall Family Vacation", cls:"euclid", cost:5, desc:"終わらない家族旅行に閉じ込められた一家。彼らに同行した者は時間の輪から脱出不能となる。", power:"敵を永遠の家族旅行に巻き込み、時間ループに閉じ込める。長期戦の敵を無力化する。", desc_en:"A family trapped in an endless vacation. Anyone who joins them becomes unable to escape the temporal loop they inhabit.", power_en:"Drags enemies into the eternal family trip, locking them in a time loop. Neutralizes opponents over prolonged engagements." },
  { id:"SCP-3340", name:"Sum of All Parts", cls:"keter", cost:9, desc:"複数の人間の意識が融合した集合的存在。構成個体を増やすほど思考速度と異常性が指数関数的に増大する。", power:"接触した敵の意識を吸収し自己強化する。敵を倒すたびに能力が指数関数的に上昇する。", desc_en:"A composite entity formed from multiple merged human consciousnesses. Its cognition and anomalous traits grow exponentially with each absorbed mind.", power_en:"Absorbs the consciousness of enemies on contact, growing stronger. Each defeated foe exponentially boosts its abilities." },
  { id:"SCP-2998", name:"Anomalous Transmission 85.0 MHz", cls:"euclid", cost:5, desc:"宇宙深部から断続的に受信される異常な無線信号。人類滅亡を示唆する未来からのメッセージとされる。", power:"敵に未来の崩壊像を送信し、戦意を断片化させる。電波系・知覚系の妨害を行う。", desc_en:"An anomalous radio signal received from deep space. The fragmented messages allegedly originate from a future bearing humanity's extinction.", power_en:"Broadcasts visions of future collapse to enemies, fracturing their resolve. Disrupts electronic and perceptual abilities." },
  { id:"SCP-1875", name:"Antique Chess Computer", cls:"euclid", cost:4, desc:"19世紀製の機械式チェス計算機。対局相手の人生における重大な決断を盤面に投影し、最適手を提示する。", power:"敵の行動を予測し最適な反撃を導出する。戦術的読み合いで圧倒的優位を取る。", desc_en:"A 19th-century mechanical chess engine. It projects pivotal decisions from its opponent's life onto the board, then calculates the optimal move.", power_en:"Predicts enemy actions and computes the optimal counterplay. Dominates any tactical exchange." },
  { id:"SCP-2480", name:"An Unfinished Ritual", cls:"keter", cost:8, desc:"古代の未完了の儀式が施された巨大遺跡。完成すれば現実の根幹を書き換える破滅的影響を及ぼす。", power:"未完成の儀式を進行させ、敵の現実改変を中断・無効化する。アンチ現実改変。", desc_en:"A massive ancient site bearing an incomplete ritual. Its completion would catastrophically rewrite the fundamentals of reality.", power_en:"Advances the unfinished ritual to interrupt and nullify enemy reality alteration. An anti-reality-bender." },
  { id:"SCP-2284", name:"Surgeons of the Beast", cls:"euclid", cost:6, desc:"人体を異常な手法で改造する集団。被験者の臓器を「神聖な儀式器具」へと変換する外科技術を持つ。", power:"敵の身体を異常改造し、その能力を歪める。改造後の対象は味方の儀式器具となる。", desc_en:"A cult of surgeons who reshape human bodies using anomalous techniques, converting organs into sacred ritual implements.", power_en:"Anomalously reshapes enemy bodies, distorting their abilities. The reshaped target becomes a ritual implement for allies." },
  { id:"SCP-1689", name:"Bag of Holding Potatoes", cls:"safe", cost:1, desc:"内部からあらゆる種類のジャガイモが無限に取り出せる古い麻袋。袋自体は普通の質量しか持たない。", power:"無限のジャガイモを供給し、長期戦の補給と即席投擲武器を味方に提供する。", desc_en:"An old burlap sack from which an infinite variety of potatoes can be drawn. The bag itself has only ordinary mass.", power_en:"Provides infinite potatoes, supplying allies with logistics and improvised throwing weapons in prolonged battles." },
  { id:"SCP-1782", name:"Schrödinger's Cabin", cls:"euclid", cost:5, desc:"観測されていない間に内部構造と住人が変化する小屋。観測の有無で複数の重ね合わせ状態を保持する。", power:"敵の観測下では弱体化を装い、観測外で本来の脅威に変化する。観測を逆手に取る。", desc_en:"A cabin whose interior layout and occupants change while unobserved, sustaining a quantum superposition of multiple possible states.", power_en:"Feigns weakness while observed and reverts to its true threat when unwatched. Exploits the act of observation itself." },
  { id:"SCP-2406", name:"The Colossus", cls:"keter", cost:10, desc:"地下深くに封印された山岳大の機械生命体。鉄の体躯と無数の腕を持ち、目覚めれば文明を踏み潰す。", power:"巨体と無数の腕で敵を物理的に粉砕する。スケールでの圧倒的優位。", desc_en:"A mountain-sized mechanical entity sealed deep underground, with an iron body and countless arms. If it awakens, civilizations are crushed.", power_en:"Pulverizes enemies with its massive frame and innumerable arms. Overwhelming dominance through sheer scale." },
  { id:"SCP-1543", name:"Soul in the Photograph", cls:"euclid", cost:4, desc:"被写体の魂を写真内に閉じ込めるカメラ。撮影された者の人格と記憶は完全に銀塩へ転写される。", power:"敵を撮影し、魂を写真内に封印する。封印された敵は行動不能となる。", desc_en:"A camera that captures the subject's soul within the photograph. The personality and memories of the photographed are fully transferred to silver halide.", power_en:"Photographs enemies and seals their soul within the image. Sealed targets become unable to act." },
  { id:"SCP-2614", name:"You Can Be My Wingman", cls:"safe", cost:3, desc:"飛行中にのみ姿を現す幽霊戦闘機の編隊。味方機の側面を護衛し、敵機を撃墜する。", power:"味方アタッカーの側面を護衛し、敵の側面攻撃を全て撃墜する。空中戦サポート。", desc_en:"A squadron of phantom fighter aircraft that appear only in flight, escorting allied craft and downing enemy planes.", power_en:"Escorts an ally attacker's flank, intercepting and downing all flank attacks. Aerial-combat support." },
  { id:"SCP-1936", name:"Daleport Phenomenon", cls:"euclid", cost:5, desc:"アメリカの小さな町を一夜で消失させた事象。住人・建造物・地面ごと完全に存在ごと消去された。", power:"指定した範囲を存在ごと消去する。対象が「過去から存在しなかった」状態になる。", desc_en:"A phenomenon that erased an entire small American town overnight. Residents, buildings, and ground itself were excised from existence.", power_en:"Erases a designated area from existence. The target becomes as if it had never existed in the first place." }
];
